insert into public.pathway_stages (id, name, short_name, subtitle, ball_color, purpose, priorities, non_negotiables, common_mistakes, competition_expectations, advancement_expectations, advancement_owner, content_status, sort_order) values ('foundations', 'Tier 1 Foundations', 'Foundations', 'Red Ball & Orange Ball', 'red-orange', 'Build athletic literacy, balance, coordination, rhythm, listening, effort habits, basic grips, rallying, movement habits, and early tennis discipline. This level should still be engaging and fun, but it should have real structure and clear standards. Kids should start learning how to move, focus, follow direction, and train with purpose from the beginning.', '{"Athletic literacy and movement fundamentals","Balance, coordination, and rhythm","Basic grip introduction","Rallying and ball tracking","Listening and effort habits","Early discipline and focus"}', '{"Every session has structure — not just free play","Players learn to listen and follow direction","Effort and attitude are coached, not ignored","Basic movement patterns are taught correctly from day one"}', '{"Making it purely recreational with no standards","Skipping athletic literacy for stroke technique too early","Not coaching effort and behavior","Rushing players to Orange Ball before readiness"}', 'Score awareness and basic match play introduction. Red Ball tournaments encouraged for exposure.', 'Player shows consistent effort, basic rally skills, movement readiness, and behavioral maturity to handle Orange Ball structure.', 'Max', 'complete', 1) on conflict (id) do nothing;
insert into public.pathway_stages (id, name, short_name, subtitle, ball_color, purpose, priorities, non_negotiables, common_mistakes, competition_expectations, advancement_expectations, advancement_owner, content_status, sort_order) values ('prep', 'Tier 1 Prep', 'Prep', 'Green Ball', 'green', 'Develop stronger spacing, footwork, rally tolerance, topspin, directional control, serve and return structure, point awareness, decision making, and early competition habits. Players should not be rushed through this level. It is a key bridge between early development and yellow ball training.', '{"Grip changes and contact point development","Movement in multiple directions","Open stance development","Playing on the rise","Changing direction and exploiting weaknesses","Transition patterns and overhead accuracy","Serve placement and doubles basics","Emotional control in competition"}', '{"Players must develop real footwork, not just hit from a standing position","Topspin must be introduced with proper mechanics","Competition is part of training, not separate from it","Players should not be rushed to yellow ball"}', '{"Rushing to yellow ball before Green Ball competencies are solid","Ignoring footwork in favor of stroke production","Not enough live ball and point play","Skipping serve and return development"}', 'Regular Green Ball tournament participation. Players should be developing competitive habits and emotional control.', 'Player demonstrates grip changes, directional control, serve placement, emotional regulation, and readiness for full court yellow ball play.', 'Rebeka', 'complete', 2) on conflict (id) do nothing;
insert into public.pathway_stages (id, name, short_name, subtitle, ball_color, purpose, priorities, non_negotiables, common_mistakes, competition_expectations, advancement_expectations, advancement_owner, content_status, sort_order) values ('jasa', 'Tier 1 JASA', 'JASA', 'Early Yellow Ball Competitive', 'yellow', 'Build full court skills, depth and direction, tactical awareness, pace tolerance, transition play, serve and return quality, tournament habits, accountability, resilience, and independence. JASA should feel serious and developmental, not casual.', '{"Full court pace and depth","Extension through the hitting zone","Wider lower base and deeper movement patterns","Tactical use of the forehand","Transition competence and attacking short balls","Serve targets and compact returns","Open court patterns","Independence, resilience, and self-analysis"}', '{"Sessions must feel serious and developmental","Players must be accountable for effort and attitude","Tournament participation is expected","Self-analysis and independence are actively coached"}', '{"Treating JASA as casual or recreational","Not pushing players on accountability","Ignoring tactical development in favor of just hitting","Not building tournament readiness into training"}', 'Regular yellow ball tournament play. UTR readiness. Players should be competing with intent and learning from results.', 'Player shows full court competence, tactical awareness, competitive maturity, and readiness for higher intensity training environments.', 'Rebeka', 'partial', 3) on conflict (id) do nothing;
insert into public.pathway_stages (id, name, short_name, subtitle, ball_color, purpose, priorities, non_negotiables, common_mistakes, competition_expectations, advancement_expectations, advancement_owner, content_status, sort_order) values ('hs', 'Tier 1 HS', 'HS', 'High School Pathway', null, 'Maintain Tier 1 culture and intensity while serving players who either want to push toward stronger Tier 1 levels or maximize their high school tennis and long term growth. HS should still reflect real standards and progression, even if it serves a broader range of long term outcomes.', '{"Maintaining Tier 1 standards and culture in every session","Competitive preparation for high school team play","Continued technical refinement under pressure","Tactical awareness and pattern execution in match play","Physical fitness, endurance, and injury prevention","Leadership development and team dynamics","Doubles strategy and communication","Mental toughness for dual-match pressure situations"}', '{"Tier 1 culture and intensity are maintained regardless of competitive level","Players are held to real standards — HS is not a casual track","Training is purposeful with clear session objectives every day","Players demonstrate leadership on and off the court"}', '{"Lowering standards because players are "just doing high school tennis"","Not providing enough structure or progression within the HS track","Treating HS as a holding group rather than a development environment","Ignoring doubles development and team play skills","Failing to connect HS training to long-term development goals"}', 'High school team play plus additional tournament participation based on individual goals. Players should be competing with intent in both team and individual settings.', 'Movement to ASA or FTA requires demonstrated commitment, competitive results, leadership qualities, and approval from Jon and Filipp.', 'Jon & Filipp', 'partial', 4) on conflict (id) do nothing;
insert into public.pathway_stages (id, name, short_name, subtitle, ball_color, purpose, priorities, non_negotiables, common_mistakes, competition_expectations, advancement_expectations, advancement_owner, content_status, sort_order) values ('asa', 'Tier 1 ASA', 'ASA', 'After School Academy', null, 'Train serious competitive players with strong standards, full commitment, structured fitness expectations, and clear tournament alignment. Players in this environment should be highly invested in development and pursuing strong competitive outcomes. ASA represents a significant step up in intensity, accountability, and expectation.', '{"High-level competitive preparation and match-play integration","Structured fitness and physical development through APL","Advanced tactical training — pattern execution under pressure","Tournament alignment, scheduling, and goal setting","Mental toughness, competitive resilience, and composure","Full commitment to the development process and training schedule","Weapon development — building a signature game style","Advanced serve and return as primary weapons"}', '{"Full commitment to training schedule — attendance matters","Structured fitness expectations are met through APL integration","Tournament participation is aligned with development goals","Players demonstrate professional conduct at all times","Every session has clear tactical and technical objectives"}', '{"Allowing players to coast without accountability","Not integrating fitness into the training plan","Lack of tournament planning and alignment with development goals","Treating ASA like an advanced clinic instead of a competitive training environment","Not demanding enough from players who have earned this level"}', 'Strong tournament schedule with clear goals. Players should be pursuing meaningful competitive outcomes and tracking UTR progression.', 'Movement to FTA requires exceptional commitment, competitive results, physical readiness for full-time training, and leadership approval from Jon and Filipp.', 'Jon & Filipp', 'partial', 5) on conflict (id) do nothing;
insert into public.pathway_stages (id, name, short_name, subtitle, ball_color, purpose, priorities, non_negotiables, common_mistakes, competition_expectations, advancement_expectations, advancement_owner, content_status, sort_order) values ('fta', 'Tier 1 FTA', 'FTA', 'Full Time Academy', null, 'This is the highest commitment training environment at Tier 1. It combines on-court development, match play, structure, physical development through APL, mental performance training, and long-term college or elite competitive preparation. FTA represents the most complete and demanding development environment in the system.', '{"Elite on-court development with individualized programming","Comprehensive physical training through APL — strength, speed, endurance","Match play integration — training must transfer to competition","College recruitment preparation or elite competitive pathway","Mental performance, visualization, and pressure management","Complete athlete development — on and off the court","Video analysis and tactical planning for upcoming opponents","Professional habits — nutrition, recovery, time management"}', '{"Highest level of commitment and professionalism expected","Complete integration of on-court, fitness, and mental training","Clear competitive pathway and measurable goals","Exemplary conduct and leadership — FTA players set the standard","Full accountability for training, competition, and personal development"}', '{"Not demanding enough from players at this level","Lack of integrated training approach — on-court isolated from fitness","Not maintaining the highest professional standards in every interaction","Failing to individualize programming for each player''s competitive goals","Not connecting daily training to long-term recruitment or competitive outcomes"}', 'Full competitive schedule aligned with college recruitment or elite competitive goals. Players should be competing nationally and tracking measurable outcomes.', 'FTA is the highest level in the Tier 1 pathway. Development continues within this environment toward individual competitive goals — college placement, professional development, or elite amateur competition.', 'Jon & Filipp', 'partial', 6) on conflict (id) do nothing;
