insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('f-warmup-1', 'Animal Movement Relay', '{"foundations"}', 'warmup', 'physical', 'both', 'cooperative', 'Build athletic literacy through movement patterns — bear crawls, crab walks, frog jumps, and lateral shuffles.', 'Set up 4 cones in a line, 3 meters apart. Players line up at the start. Each cone marks a different animal movement.', '8-10 min', '{"Stay low through the bear crawl","Push off both feet on frog jumps","Eyes up, not on the ground","Move with purpose, not just speed"}', '{"Players complete each movement with correct form","Players maintain effort throughout"}', '{"Rushing through movements without proper form","Standing up too tall during crawls","Losing focus between stations"}', 'Add a tennis ball carry — players must balance a ball on the racket while completing movements.', 'Reduce to 2 movements and shorter distances.', 'Relay race format — two teams, first team to complete all movements wins.', 'Athletic literacy is the foundation of all court movement. Players who move well athletically will move well on court.', null, null, null, 1) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('f-warmup-2', 'Catch & Throw Circuit', '{"foundations"}', 'warmup', 'physical', 'both', 'cooperative', 'Develop hand-eye coordination, throwing mechanics, and catching skills that transfer to racket skills.', 'Partners face each other 3-4 meters apart. Use foam balls or tennis balls. Cycle through underhand throw, overhand throw, and bounce catch.', '8 min', '{"Step toward your target when throwing","Soft hands when catching","Track the ball with your eyes all the way in","Use your whole body, not just your arm"}', '{"Players can catch 7 out of 10 throws consistently","Throwing motion uses proper weight transfer"}', '{"Catching with stiff arms","Not stepping into throws","Losing focus between catches"}', 'Increase distance. Add movement — catch while shuffling sideways.', 'Use larger foam balls. Decrease distance to 2 meters.', 'Count consecutive catches — which pair can get the longest streak?', 'Throwing mechanics mirror the serve motion. Catching develops the tracking and soft hands needed for volleys.', null, null, null, 2) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('f-warmup-3', 'Rhythm Skipping & Cone Agility', '{"foundations"}', 'warmup', 'physical', 'both', 'cooperative', 'Develop rhythm, coordination, and agility through structured movement patterns with cones.', 'Set up a zigzag cone pattern. Players skip through the cones, then shuffle laterally, then backpedal to start. Repeat 3-4 rounds.', '6-8 min', '{"Stay on the balls of your feet","Pump your arms — they help you move","Quick feet through the cones, not big steps","Keep your head up and eyes forward"}', '{"Players maintain rhythm through the full pattern","Feet stay light and quick through cone changes"}', '{"Heavy, flat-footed movement","Losing the rhythm pattern","Cutting corners instead of moving through each cone"}', 'Add a racket — players carry the racket while completing the agility course.', 'Slow the tempo. Walk through the pattern first before adding speed.', 'Time trial — each player tries to beat their previous best time.', 'Rhythm and agility are the building blocks of on-court movement. Players who can change direction quickly recover better between shots.', null, null, null, 3) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('f-movement-1', 'Split Step Reaction Game', '{"foundations"}', 'movement', 'movement', 'both', 'cooperative', 'Teach the split step as a fundamental movement habit. Players learn to time their split with the coach''s contact.', 'Players stand at the baseline in ready position. Coach stands at the net with a ball. Coach tosses or hits — players split step and move to the ball.', '10 min', '{"Land on the balls of your feet","Split when I make contact, not after","Stay low and balanced","First step should be explosive"}', '{"Players consistently split step before moving","Landing is balanced with knees bent"}', '{"Flat-footed landing","Splitting too late","Standing up tall after the split instead of staying low"}', 'Add directional cues — coach points left or right after the split.', 'Use verbal cues ("split!") before visual cues.', 'Simon Says format — coach mixes real feeds with fake cues.', 'The split step is the single most important movement habit in tennis. It must become automatic.', null, null, null, 4) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('f-movement-2', 'Shadow Swing Rally', '{"foundations"}', 'movement', 'movement', 'both', 'cooperative', 'Build movement patterns and swing preparation without the pressure of hitting a ball. Players shadow their strokes while moving.', 'Players line up on the baseline. Coach calls out "forehand" or "backhand" and a direction. Players shuffle, set up, and shadow swing, then recover to center.', '8 min', '{"Turn your shoulders first, then move your feet","Recover to the center after every shadow swing","Make the shadow swing look like a real swing — full follow through","Stay low and balanced throughout"}', '{"Players demonstrate proper unit turn on every shadow swing","Recovery to center is consistent"}', '{"No shoulder turn — just moving the arm","Not recovering to center between swings","Rushing through without proper form"}', 'Add a ball — coach feeds after the shadow swing setup.', 'Coach demonstrates each movement before players attempt it.', 'Mirror drill — one player leads, the other mirrors the movement and swing.', 'Shadow swings build muscle memory for preparation and recovery. Players who prepare well hit better shots.', null, null, null, 5) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('f-feeding-1', 'Target Rallying to Center', '{"foundations"}', 'feeding', 'baseline', 'feeding', 'technical', 'Develop consistent contact and rally direction by hitting to a center target zone.', 'Place a target zone (cones or lines) in the center of the opposite court. Coach feeds from the net. Player hits forehands and backhands aiming for the target.', '12 min', '{"Turn your shoulders before you swing","Watch the ball onto the racket","Follow through toward your target","Feet first, then swing"}', '{"Player hits 6 out of 10 balls into the target zone","Consistent unit turn before contact"}', '{"No shoulder turn — arm-only swing","Watching the target instead of the ball","Feet planted — not adjusting to the feed"}', 'Move the target to crosscourt or down the line. Add movement before the feed.', 'Larger target zone. Slower, more predictable feeds.', 'Points for hitting the target — first to 10 wins.', 'Rallying to the center is the foundation of consistency. Players must be able to sustain a rally before they can direct one.', null, null, null, 6) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('f-feeding-2', 'Volley Introduction — Catch and Hit', '{"foundations"}', 'feeding', 'transition', 'feeding', 'technical', 'Introduce the volley through a catch-then-hit progression. Build soft hands and continental grip awareness.', 'Player stands at the service line. Coach feeds gently from across the net. Start with catching the ball, then progress to volleying with the racket.', '10 min', '{"Catch the ball out in front","Firm wrist, no big swing","Step forward into the ball","Continental grip — like shaking hands with the racket"}', '{"Player can volley 5 out of 10 feeds over the net","Continental grip is attempted consistently"}', '{"Swinging at the volley instead of punching","Wrist is floppy on contact","Standing too far back from the net"}', 'Alternate forehand and backhand volleys. Add a target.', 'Stay with catching only. Use a foam ball.', 'Volley rally — how many volleys can the pair keep going?', 'Net play is essential at every level. Early volley habits set the foundation for approach and transition play later.', null, null, null, 7) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('f-feeding-3', 'Forehand Grip Check — Feed and Freeze', '{"foundations"}', 'feeding', 'baseline', 'feeding', 'technical', 'Reinforce correct forehand grip by having players freeze at contact point for coach inspection.', 'Coach feeds from the net. Player hits a forehand and freezes at the contact point. Coach checks grip, racket face angle, and contact position.', '10 min', '{"Find your forehand grip before the ball comes","Freeze at contact — hold it there","Racket face should point toward your target","Contact point is in front of your body, not beside it"}', '{"Player demonstrates correct grip on 7 out of 10 feeds","Contact point is consistently in front of the body"}', '{"Grip slipping to continental during the swing","Contact point too far behind the body","Not freezing long enough for the coach to check"}', 'Add backhand grip check. Alternate forehand and backhand feeds.', 'Coach physically places the player''s hand in the correct grip before each feed.', 'Grip quiz — coach calls "forehand" or "backhand" and player must show the correct grip within 2 seconds.', 'The grip is the connection between the player and the racket. Correct grip habits must be established early or they become difficult to fix later.', null, null, null, 8) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('o-movement-1', 'Crossover Step Recovery Drill', '{"foundations"}', 'movement', 'movement', 'feeding', 'technical', 'Develop the crossover step and recovery pattern. Players learn to move wide and recover to center efficiently.', 'Player starts at center mark. Coach feeds alternating wide forehands and backhands. Player must use crossover step to reach the ball and recover to center.', '12 min', '{"Cross the outside foot over first","Push off the outside foot to recover","Stay low through the recovery","Split step before the next ball"}', '{"Consistent crossover step on wide balls","Recovery to center between shots"}', '{"Shuffling instead of crossing over","Not recovering to center","Standing up between shots"}', 'Increase feed pace and width. Add a third ball.', 'Slower feeds. Only one direction at a time.', 'Count successful recoveries — beat your personal best.', 'The crossover recovery is how players cover the court in real rallies. Without it, players are always late to the next ball.', null, null, null, 9) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('o-feeding-1', 'Topspin Introduction — Brush Up', '{"foundations"}', 'feeding', 'baseline', 'feeding', 'technical', 'Introduce topspin mechanics through a low-to-high swing path. Players learn to brush up on the ball.', 'Player at baseline. Coach feeds from the net at moderate pace. Focus on low-to-high racket path. Place a rope or line 3 feet above the net as a visual target.', '15 min', '{"Start the racket below the ball","Brush up the back of the ball","Finish high over your shoulder","Let the spin do the work — don''t muscle it"}', '{"Player demonstrates visible topspin on 5 out of 10 balls","Low-to-high swing path is consistent"}', '{"Flat swing path — no brush","Dropping the racket head too much","Trying to hit too hard instead of focusing on spin"}', 'Add directional targets. Increase feed pace.', 'Use a foam ball to exaggerate spin. Hand-feed from close range.', 'Spin challenge — who can make the ball bounce highest on the other side?', 'Topspin is the primary tool for controlling depth and consistency in rallies. It must be developed early and reinforced constantly.', null, null, null, 10) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('o-serve-1', 'Serve Toss & Trophy Position', '{"foundations"}', 'serve-return', 'serve-return', 'both', 'technical', 'Build a consistent toss and teach the trophy position as the foundation of the serve motion.', 'Players stand at the baseline with a basket of balls. Focus on toss placement (slightly in front, at 1 o''clock) and freezing in the trophy position.', '10 min', '{"Toss with your fingertips, not your palm","Release the ball at eye level","Trophy position — racket behind your head, elbow high","Hold the trophy position for 2 seconds before swinging"}', '{"Toss lands within a racket length in front consistently","Trophy position shows proper arm and racket alignment"}', '{"Toss going behind the head","Dropping the elbow in trophy position","Rushing through the motion without pausing"}', 'Connect the trophy position to a full serve motion. Add a target in the service box.', 'Practice toss only — 20 tosses aiming for a target on the ground.', 'Toss accuracy challenge — place a hoop on the ground and see who can land the most tosses inside it.', 'The toss controls the entire serve. A consistent toss leads to a consistent serve. The trophy position is the power position for all serve types.', null, null, null, 11) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('o-points-1', 'Mini Court Points — Service Box Only', '{"foundations"}', 'points', 'tactical', 'live-ball', 'competitive', 'Introduce point play in a small court setting. Develop touch, placement, and competitive habits.', 'Two players play points using only the service boxes. Underhand serve to start. First to 5 points.', '10 min', '{"Use soft hands — this is about placement, not power","Move your opponent around the box","Recover to the middle after every shot","Compete on every point — no free points"}', '{"Players sustain rallies of 4+ shots","Players show tactical intent in shot placement"}', '{"Hitting too hard for the small court","Standing still instead of recovering","Not keeping score or competing with intent"}', 'Expand to half court. Add volleys as an option.', 'Cooperative rallying in the service box first — count consecutive balls before adding competition.', 'King of the Mini Court — winner stays, loser rotates.', 'Mini court points develop touch, feel, and competitive habits in a controlled environment. These skills transfer directly to full court play.', null, null, null, 12) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('o-comp-1', 'Around the World Relay', '{"foundations"}', 'competitive-finish', 'physical', 'both', 'competitive', 'High-energy competitive finish that reinforces movement, hustle, and team spirit.', 'Players form two lines behind the baseline. Coach feeds a ball. First player hits and runs around the net post to the other side. Next player goes. Continuous rotation.', '8 min', '{"Sprint around the post — no walking","Hit and move immediately","Encourage your teammates","Every ball counts — no lazy swings"}', '{"Players maintain full effort throughout","Balls are hit with intent, not just tapped over"}', '{"Walking instead of sprinting","Not being ready when it is your turn","Losing energy as the drill continues"}', 'Add a rule — if the ball doesn''t land in the court, the team loses a life.', 'Slower rotation. Coach feeds easier balls.', 'This is already competitive. Add elimination — miss the court and you sit out.', 'Energy, hustle, and competing under fatigue are essential match play qualities. This drill builds all three.', null, null, null, 13) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p-warmup-1', 'Topspin Short Court Rally', '{"prep"}', 'warmup', 'baseline', 'live-ball', 'cooperative', 'Warm up with topspin in a controlled short court setting. Reinforce spin, feel, and consistency.', 'Two players rally inside the service boxes. Both players must use topspin on every ball. Focus on height over the net and spin rather than pace.', '8 min', '{"Brush up on every ball — no flat shots","Get the ball 3-4 feet over the net with spin","Move your feet between shots","Control the rally — this is about feel, not power"}', '{"Players sustain 15+ ball rallies with topspin","Visible spin on 80% of shots"}', '{"Hitting flat instead of with spin","Trying to hit winners in the warm up","Standing still between shots"}', 'Add a slice only round. Alternate topspin and slice.', 'Allow any spin. Focus on rally length only.', 'Longest rally challenge — which pair can sustain the longest topspin rally?', 'Short court topspin rallies develop the feel and spin control needed for consistent baseline play at the Green Ball level.', null, null, null, 14) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p-movement-1', 'Open Stance Footwork Circuit', '{"prep"}', 'movement', 'movement', 'feeding', 'technical', 'Develop the open stance as a primary hitting position. Build the footwork pattern for loading and rotating.', 'Player starts at center. Coach feeds wide forehands. Player must set up in open stance, load on the outside foot, rotate through the shot, and recover.', '12 min', '{"Load on your outside foot — feel the ground","Rotate your hips through the shot","Don''t fall sideways — stay balanced","Push off the back foot to recover"}', '{"Player demonstrates proper open stance on 7 out of 10 wide forehands","Weight transfer and rotation are visible"}', '{"Stepping across instead of loading open","No hip rotation — arm-only swing","Falling off balance after the shot"}', 'Add a second ball — player must recover and hit a second shot after the open stance forehand.', 'Coach demonstrates the footwork pattern. Player shadows before hitting.', 'Count clean open stance forehands in a row — beat your personal best.', 'The open stance is the primary hitting position for wide balls in modern tennis. Players who master it cover the court more efficiently.', null, null, null, 15) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p-feeding-1', 'Directional Rally — Own the Crosscourt', '{"prep"}', 'feeding', 'baseline', 'live-ball', 'tactical', 'Develop crosscourt rally consistency and the ability to own a direction. Players learn to sustain crosscourt rallies with depth and spin.', 'Two players rally crosscourt (forehand or backhand). Cones mark the target zone deep crosscourt. Rally must stay in the crosscourt half.', '15 min', '{"Aim deep crosscourt — past the service line","Use topspin to keep the ball in","Move your feet between shots — don''t be lazy","Own this direction — make it your rally"}', '{"Players sustain 8+ ball crosscourt rallies","Majority of balls land past the service line"}', '{"Changing direction too early","Balls landing short in the service box","Not recovering between shots"}', 'Add a "change direction" rule — after 6 crosscourt balls, player can go down the line.', 'Reduce to 4-ball rally targets. Allow full court.', 'First pair to reach 20 consecutive crosscourt balls wins.', 'The crosscourt rally is the most common pattern in match play. Players who can own the crosscourt control the point.', null, null, null, 16) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p-feeding-2', 'Approach Shot — Short Ball Attack', '{"prep"}', 'feeding', 'transition', 'feeding', 'tactical', 'Teach players to recognize and attack short balls with an approach shot, then close to the net.', 'Coach feeds a deep ball then a short ball. Player hits the deep ball, recognizes the short ball, approaches, and finishes at the net with a volley.', '15 min', '{"Read the short ball early","Move through the ball — don''t stop and hit","Approach deep to the open court","Close to the net after the approach — don''t hang back"}', '{"Player recognizes short ball within 1 second","Approach shot lands deep","Player closes to net position"}', '{"Hitting the approach and staying at the baseline","Approaching to the middle instead of the open court","Not splitting at the net before the volley"}', 'Add a live ball passing shot from the opponent.', 'Feed only the short ball — remove the deep ball setup.', 'Play points starting with a short ball — approach and finish.', 'Attacking short balls is how players transition from defense to offense. This pattern wins points at every level.', null, null, null, 17) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p-feeding-3', 'Backhand Slice — Shape and Control', '{"prep"}', 'feeding', 'baseline', 'feeding', 'technical', 'Develop the backhand slice as a tactical tool. Build proper technique with continental grip and high-to-low swing path.', 'Coach feeds to the backhand side. Player hits slice backhands aiming deep crosscourt. Focus on continental grip, open racket face, and follow through.', '12 min', '{"Continental grip — same as your volley grip","High to low swing path — cut under the ball","Keep the ball low over the net","Follow through toward your target, not down into the ground"}', '{"Player demonstrates proper slice technique on 6 out of 10 balls","Ball stays low after the bounce"}', '{"Using an eastern grip instead of continental","Chopping down instead of slicing through","Ball floating high with no bite"}', 'Add a target deep in the court. Mix slice and topspin backhands.', 'Hand-feed from close range. Focus on the grip and swing path only.', 'Slice rally — two players rally using only slice. Longest rally wins.', 'The slice is a defensive and transitional weapon. It changes the pace, stays low, and sets up approach shots.', null, null, null, 18) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p-serve-1', 'Serve Placement — Targets', '{"prep"}', 'serve-return', 'serve-return', 'feeding', 'technical', 'Develop serve placement by aiming at specific targets in the service box. Build the habit of serving with intent.', 'Place targets (cones or towels) in the corners of the service box — wide, body, and T. Player serves sets of 5 to each target.', '12 min', '{"Toss in front and slightly to the right (for righties)","Use your legs — push up into the serve","Aim for a target every time — no aimless serves","Smooth motion — don''t rush"}', '{"Player hits 3 out of 5 serves into the correct service box","At least 1 out of 5 hits the intended target zone"}', '{"Inconsistent toss","No leg drive","Aiming without adjusting the toss location"}', 'Add a returner. Serve and play the point.', 'Move closer to the net. Focus on toss and motion only.', 'Target challenge — points for hitting each zone. First to 10 wins.', 'The serve is the only shot you control completely. Placement turns the serve from a start to a weapon.', null, null, null, 19) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p-liveball-1', 'Rally to Pattern — Crosscourt to Down the Line', '{"prep"}', 'liveball', 'tactical', 'live-ball', 'tactical', 'Develop the fundamental rally pattern: build crosscourt, then change direction down the line when the opportunity appears.', 'Two players rally crosscourt. After 4+ crosscourt balls, one player changes direction down the line. Point is played out from there.', '15 min', '{"Build the point crosscourt first — be patient","Change direction when you get a short ball or a ball in your strike zone","Commit to the direction change — don''t go tentative","After the direction change, close the court"}', '{"Players sustain 4+ crosscourt balls before changing direction","Direction change is intentional and aggressive"}', '{"Changing direction too early without building the point","Going down the line from a defensive position","Not closing the court after the direction change"}', 'Play full points starting crosscourt. Player must build and change direction.', 'Coach feeds crosscourt. Player practices the direction change only.', 'Bonus point for a clean direction change winner.', 'The crosscourt-to-down-the-line pattern is the most fundamental tactical sequence in tennis. It is how points are constructed.', null, null, null, 20) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p-points-1', 'King of the Court — Green Ball', '{"prep"}', 'points', 'tactical', 'live-ball', 'competitive', 'Competitive point play with rotation. Players learn to compete under pressure and apply patterns.', 'One player on the "King" side, challengers line up on the other side. Coach feeds to start the point. Winner stays, loser rotates.', '15 min', '{"Play with intent — have a plan for each point","Use your patterns — crosscourt to set up, down the line to finish","Compete on every point, not just the easy ones","Reset mentally between points"}', '{"Players compete with visible intent and effort","Patterns from training appear in point play"}', '{"Passive play — just pushing the ball back","No plan on the point","Getting emotional after losing a point"}', 'Add serve and return to start the point.', 'Coach feeds easier balls. Allow more time between points.', 'This is already competitive. Add a "must win 3 in a row to become King" rule.', 'King of the Court teaches players to compete under pressure with consequences — exactly like a real match.', null, null, null, 21) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p-doubles-1', 'Doubles Positioning — I Formation Introduction', '{"prep"}', 'points', 'doubles', 'live-ball', 'tactical', 'Introduce basic doubles positioning and communication. Build awareness of net player responsibilities.', 'Two teams of two. Server and net player set up. Focus on net player positioning, poaching signals, and communication.', '15 min', '{"Net player — stay active, not a statue","Communicate before every point — who is covering what","Server — get your first serve in and follow the plan","Close together at the net — don''t leave gaps"}', '{"Teams communicate before each point","Net player attempts at least 2 poaches per game"}', '{"No communication between partners","Net player standing still and not engaging","Both players on the same side of the court"}', 'Add I-formation. Net player signals before the serve.', 'One-up, one-back formation only. Focus on basic positioning.', 'Doubles tiebreaker — first team to 7 with serve rotation.', 'Doubles is a critical part of team tennis and tournament play. Communication and positioning are the foundation of doubles success.', null, null, null, 22) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('j-warmup-1', 'Topspin & Slice Short Court Alternation', '{"jasa"}', 'warmup', 'baseline', 'live-ball', 'cooperative', 'Warm up with alternating topspin and slice in the service box. Develop feel, touch, and spin variation.', 'Two players rally in the service boxes. Alternate: one topspin, one slice. Maintain the pattern throughout the rally.', '8 min', '{"Feel the difference between topspin and slice in your hand","Slice should stay low, topspin should bounce up","Smooth transitions between grips","Control and consistency — not pace"}', '{"Players sustain 10+ ball rallies with alternating spin","Grip changes are smooth and consistent"}', '{"Forgetting the alternation pattern","Slice floating too high","Not changing grip between shots"}', 'Add a drop shot option — player can drop shot instead of the next spin.', 'Topspin only for one round, slice only for the next.', 'If you break the pattern, your opponent gets a point.', 'Spin variation is a key tactical tool. Players who can change spin keep opponents off balance and create opportunities.', null, null, null, 23) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('j-movement-1', 'Full Court Coverage — 6 Ball Pattern', '{"jasa"}', 'movement', 'movement', 'feeding', 'technical', 'Build full court movement and recovery through a structured 6-ball feeding pattern that covers all areas of the court.', 'Coach feeds 6 balls in sequence: wide forehand, recovery, wide backhand, recovery, short ball approach, volley finish. Player must execute all 6 with proper footwork.', '15 min', '{"Split step before every ball","Crossover step on wide balls","Move through the short ball — don''t stop","Close to the net after the approach — finish the pattern"}', '{"Player completes the full 6-ball pattern with proper footwork","Recovery between shots is efficient"}', '{"Skipping the split step between balls","Not recovering to center after wide balls","Stopping at the baseline after the approach shot"}', 'Increase feed pace. Add a 7th ball — a lob after the volley.', 'Reduce to 4 balls. Slower feeds with more recovery time.', 'Score each ball — 1 point for execution, bonus point for a winner on the volley.', 'Full court coverage is what separates competitive players from recreational ones. This pattern mirrors real point construction.', null, null, null, 24) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('j-feeding-1', 'Inside-Out Forehand — Weapon Development', '{"jasa"}', 'feeding', 'baseline', 'feeding', 'tactical', 'Develop the inside-out forehand as an offensive weapon. Build the footwork and positioning to run around the backhand.', 'Coach feeds to the backhand side (slightly middle). Player runs around the backhand and hits an inside-out forehand to the opponent''s backhand corner.', '15 min', '{"Move your feet early — get around the ball","Set up in open stance on the forehand side","Hit with authority — this is your weapon","Aim deep to the opponent''s backhand corner"}', '{"Player runs around 6 out of 10 feeds successfully","Inside-out forehand lands deep in the target zone"}', '{"Not moving feet early enough — late setup","Hitting inside-in instead of inside-out","Losing balance because of rushed footwork"}', 'Add a second ball — play out the point after the inside-out forehand.', 'Coach feeds to the middle. Player practices the footwork pattern without pace pressure.', 'Inside-out forehand challenge — points for depth and placement.', 'The inside-out forehand is one of the most important offensive weapons in modern tennis. It allows players to dictate with their strongest shot.', null, null, null, 25) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('j-liveball-1', 'Full Court Rally — Depth and Direction', '{"jasa"}', 'liveball', 'baseline', 'live-ball', 'tactical', 'Build full court rally competence with emphasis on depth, direction, and pace tolerance.', 'Two players rally full court. Target zone is the last 3 feet of the court (deep zone). Players must sustain rallies while maintaining depth.', '15 min', '{"Extend through the hitting zone","Aim deep — the back fence is your friend","Use topspin to control depth at pace","Move your opponent — don''t just rally to the middle"}', '{"Players sustain 10+ ball rallies with depth","70% of balls land in the deep zone"}', '{"Balls landing in the service box","No directional intent — just hitting to the middle","Losing depth when pace increases"}', 'Add a "change direction after 8 balls" constraint.', 'Reduce to crosscourt only. Lower pace requirement.', 'Deep zone rally — any ball that lands short of the service line loses the point.', 'Depth is the most important tactical weapon in baseline tennis. Players who control depth control the rally.', null, null, null, 26) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('j-liveball-2', 'Transition Drill — Approach, Volley, Overhead', '{"jasa"}', 'liveball', 'transition', 'live-ball', 'tactical', 'Build the complete transition sequence: approach shot, split step at net, volley, and overhead finish.', 'Two players rally. Coach calls "short" and feeds a short ball. Player approaches, closes to net, and plays out the point. Opponent can pass or lob.', '15 min', '{"Approach deep and to the open court","Split step at the service line before the volley","Close the net after the first volley","If they lob, turn and track — don''t back up flat-footed"}', '{"Player executes the full transition sequence 4 out of 10 times","Split step at the net is consistent"}', '{"Staying at the baseline after the approach","No split step before the volley","Backing up on the lob instead of turning and running"}', 'Play full points with a mandatory approach on any short ball.', 'Coach feeds the short ball directly. Remove the rally setup.', 'Approach points — bonus point for finishing at the net.', 'The transition game separates one-dimensional baseliners from complete players. Approaching the net puts pressure on the opponent and shortens points.', null, null, null, 27) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('j-serve-1', 'Serve + 1 Pattern', '{"jasa"}', 'serve-return', 'serve-return', 'live-ball', 'tactical', 'Develop the serve + 1 pattern — serve with placement, then execute a planned first groundstroke.', 'Player serves to a specific target. Partner returns. Server executes a pre-planned first ball (e.g., inside-out forehand, crosscourt backhand).', '15 min', '{"Serve with a plan — know where you''re going before you toss","First ball after the serve should be aggressive","Recover quickly after the serve to set up the first ball","Own the pattern — don''t react, execute"}', '{"Player executes the planned pattern 4 out of 10 times","Serve placement sets up the pattern"}', '{"Serving without a plan","Not recovering fast enough after the serve","Abandoning the pattern after a weak return"}', 'Play out the full point after the serve + 1.', 'Coach returns instead of a partner. Predictable returns.', 'Serve + 1 points — extra point if the pattern is executed correctly.', 'The serve + 1 is the most important offensive pattern in tennis. It turns the serve into a weapon, not just a start.', null, null, null, 28) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('j-serve-2', 'Return of Serve — Block and Redirect', '{"jasa"}', 'serve-return', 'serve-return', 'live-ball', 'tactical', 'Develop a compact, reliable return of serve. Build the ability to block and redirect with depth.', 'One player serves, the other returns. Returner focuses on compact backswing, early preparation, and redirecting the serve deep crosscourt.', '12 min', '{"Short backswing — use the server''s pace","Split step as the server makes contact","Aim deep crosscourt — don''t try to do too much","Get the return in play first, then add direction"}', '{"Player returns 7 out of 10 serves in play","Returns land past the service line"}', '{"Big backswing — late on the return","No split step — flat-footed","Trying to hit a winner off the return"}', 'Add a return + 1 pattern — return deep, then execute a planned second shot.', 'Server uses a slower serve. Returner focuses on getting the ball in play only.', 'Return games — returner must win 3 out of 5 return points.', 'The return of serve is the second most important shot in tennis. A solid return neutralizes the server''s advantage and starts the point on your terms.', null, null, null, 29) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('j-points-1', 'Pressure Sets — First to 7', '{"jasa"}', 'points', 'tactical', 'live-ball', 'competitive', 'Simulate match pressure through short, intense sets. Build resilience, accountability, and competitive habits.', 'Two players play first to 7 points (win by 1). Coach feeds to start each point. Players track their own score.', '15 min', '{"Compete on every point — no throwaway points","Stay composed when you''re behind","Play your patterns under pressure","Own your score — no excuses"}', '{"Players compete with full effort throughout","Players demonstrate tactical patterns under pressure","Players manage emotions between points"}', '{"Giving up when behind","Abandoning patterns under pressure","Emotional reactions after errors"}', 'Play best of 3 sets to 7. Add serve and return.', 'First to 5 points. Coach feeds easier balls.', 'Handicap start — stronger player starts down 0-3.', 'Short sets teach players to compete under scoreboard pressure — the most important skill in tournament tennis.', null, null, null, 30) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('j-comp-1', 'Tiebreaker Simulation', '{"jasa"}', 'competitive-finish', 'tactical', 'live-ball', 'competitive', 'Simulate tiebreaker pressure. Build the mental and tactical habits needed to perform in the most critical moments of a match.', 'Two players play a full tiebreaker (first to 7, win by 2) with proper serve rotation and changeovers. Coach observes and provides feedback after.', '10-15 min', '{"Every point matters — treat it like a real match","Stick to your patterns — don''t panic","Use the changeover to reset mentally","Serve with purpose — this is not the time for double faults"}', '{"Players compete with match-level intensity","Players demonstrate composure during changeovers","Serve percentage stays above 60%"}', '{"Rushing between points","Double faulting under pressure","Abandoning patterns and going for too much"}', 'Play best of 3 tiebreakers. Add a consequence for the loser (fitness).', 'Play a shortened tiebreaker — first to 5.', 'Super tiebreaker — first to 10, win by 2.', 'Tiebreakers decide matches. Players who practice tiebreaker situations develop the composure and execution needed to win close sets.', null, null, null, 31) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('hs-warmup-1', 'Dynamic Rally Warm Up — Full Court', '{"hs"}', 'warmup', 'baseline', 'live-ball', 'cooperative', 'Full court rally warm up that builds intensity gradually. Develop rhythm and consistency at match pace.', 'Two players rally full court. Start at 50% pace, increase to 75% after 3 minutes, then 90% for the final 2 minutes.', '8-10 min', '{"Build the pace gradually — don''t start at full power","Move your feet between every shot","Use this time to find your rhythm and timing","Aim deep — warm up with purpose, not just hitting"}', '{"Players sustain rallies at each pace level","Depth is maintained as pace increases"}', '{"Starting too fast and making errors","Not moving feet — lazy warm up","Hitting to the middle with no direction"}', 'Add specific patterns — 5 crosscourt, then change direction.', 'Stay at 50-75% pace. Focus on consistency only.', 'Rally challenge — sustain 20 balls at 90% pace.', 'A structured warm up prepares the body and mind for competition. Players who warm up with purpose perform better in the first few games.', null, null, null, 32) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('hs-feeding-1', 'Groundstroke Consistency Under Pace', '{"hs"}', 'feeding', 'baseline', 'feeding', 'technical', 'Build the ability to maintain consistent groundstrokes when receiving pace. Develop timing and preparation under pressure.', 'Coach feeds at 70-80% pace to forehand and backhand alternating. Player must return every ball deep with controlled topspin.', '15 min', '{"Shorten your backswing when the pace increases","Use the incoming pace — don''t try to generate your own","Stay balanced — don''t get pushed off your base","Aim deep and let the ball do the work"}', '{"Player returns 7 out of 10 feeds deep with control","Balance is maintained throughout"}', '{"Big backswing causing late contact","Getting pushed back behind the baseline","Losing control when pace increases"}', 'Increase feed pace to 90%. Add directional targets.', 'Reduce feed pace. Focus on one side at a time.', 'Count consecutive deep returns — beat your personal best.', 'High school and tournament opponents will hit with pace. Players who can absorb and redirect pace control the baseline exchange.', null, null, null, 33) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('hs-liveball-1', 'Doubles Point Construction', '{"hs"}', 'liveball', 'doubles', 'live-ball', 'tactical', 'Develop doubles point construction — serve, return, net play, and communication as a team.', 'Two teams play doubles points. Focus on server-net player coordination, return positioning, and closing the net together.', '20 min', '{"Communicate before every point — who covers what","Net player — be active, look for the poach","Server — get the first serve in and follow the plan","Close together at the net — don''t leave the middle open"}', '{"Teams communicate before each point","Net player attempts poaches on at least 30% of points","Teams close to the net together when possible"}', '{"No communication between partners","Net player standing still","Both players staying back at the baseline"}', 'Add specific formations — Australian, I-formation.', 'One-up, one-back only. Focus on basic communication.', 'Doubles tiebreaker with serve rotation.', 'Doubles is a core part of high school team tennis. Strong doubles teams can carry a lineup. Communication and positioning are everything.', null, null, null, 34) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('hs-serve-1', 'Second Serve Development — Kick and Slice', '{"hs"}', 'serve-return', 'serve-return', 'both', 'technical', 'Develop a reliable second serve with spin variation. Build confidence in the kick serve and slice serve.', 'Player serves sets of 10 second serves. Alternate between kick serve (heavy topspin) and slice serve (sidespin). Target specific zones.', '15 min', '{"Kick serve — toss slightly behind your head, brush up","Slice serve — toss slightly to the right, brush across","Second serve must go in — no double faults","Spin is your safety net — use it"}', '{"Player makes 7 out of 10 second serves","Visible spin variation between kick and slice"}', '{"Flat second serve — no spin","Toss in the wrong position for the intended spin","Decelerating the swing instead of swinging with spin"}', 'Play points starting with second serve only. Must hold serve.', 'Focus on one serve type at a time. Build confidence before mixing.', 'Second serve challenge — 10 serves, must make 8. If not, fitness consequence.', 'The second serve is the most important serve in tennis. A weak second serve gets attacked. A strong second serve with spin keeps the server in control.', null, null, null, 35) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('hs-points-1', 'Match Simulation — Dual Match Format', '{"hs"}', 'points', 'tactical', 'live-ball', 'competitive', 'Simulate high school dual match pressure. Build the ability to compete in a team format where every match matters.', 'Players play pro sets (first to 8 games) or shortened sets. Simulate the dual match environment — teammates watching, score matters.', '20-25 min', '{"Play for the team — every game matters","Stay composed — your teammates are counting on you","Stick to your game plan — don''t try to be someone you''re not","Compete on every point regardless of the score"}', '{"Players compete with full effort throughout","Players demonstrate composure under team pressure","Players execute their game plan consistently"}', '{"Changing game plan when losing","Getting distracted by other matches","Not competing when the team score is already decided"}', 'Add team scoring — individual results contribute to team total.', 'Play shorter sets. Coach provides tactical guidance between games.', 'Team challenge — losing team does fitness.', 'High school tennis is a team sport. Players must learn to compete under the pressure of representing their team and school.', null, null, null, 36) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('asa-warmup-1', 'Competitive Rally Warm Up — Targets', '{"asa"}', 'warmup', 'baseline', 'live-ball', 'cooperative', 'Warm up with competitive intent. Rally with specific targets to build accuracy and focus from the first ball.', 'Two players rally full court. Place target cones deep in each corner. Players aim for targets while building pace gradually.', '10 min', '{"Warm up with intent — every ball has a target","Build pace gradually but maintain accuracy","Move your feet — no lazy warm ups at this level","This sets the tone for the entire session"}', '{"Players hit 50% of balls within 3 feet of targets","Pace builds to match level by minute 5"}', '{"Hitting without targets — just rallying","Starting too fast and making errors","Not moving feet between shots"}', 'Add a competitive element — first to hit 10 targets wins.', 'Remove targets. Focus on depth and consistency only.', 'Target rally — point for every ball that lands within 3 feet of a target.', 'At the ASA level, warm ups must be purposeful. The habits you build in warm up carry into competition.', null, null, null, 37) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('asa-movement-1', 'Defensive Recovery — Deep Behind the Baseline', '{"asa"}', 'movement', 'movement', 'feeding', 'tactical', 'Build the ability to defend from deep behind the baseline and recover to a neutral position. Develop the defensive movement patterns needed for high-level play.', 'Coach feeds deep, heavy balls that push the player behind the baseline. Player must defend with depth and topspin, then recover to a neutral position.', '15 min', '{"Stay low and load your legs — don''t stand up","Use heavy topspin to buy time","Aim high over the net with margin","Recover forward after the defensive shot — don''t stay back"}', '{"Player defends 6 out of 10 deep balls with depth","Recovery to neutral position after defensive shots"}', '{"Hitting flat from a defensive position","Not recovering forward after the defensive shot","Giving up on balls that push them deep"}', 'Add a second ball — player must transition from defense to offense.', 'Coach feeds at reduced pace. Focus on the recovery pattern.', 'Defensive rally — player must survive 5 defensive shots before playing out the point.', 'At the ASA level, opponents will push you deep. The ability to defend and recover is what keeps you in points and creates counterattack opportunities.', null, null, null, 38) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('asa-feeding-1', 'Weapon Development — Signature Shot Pattern', '{"asa"}', 'feeding', 'baseline', 'feeding', 'tactical', 'Develop each player''s signature offensive weapon. Build the shot that defines their game style.', 'Coach feeds balls that set up the player''s primary weapon (e.g., inside-out forehand, crosscourt backhand, drop shot). Player executes the weapon with full intent.', '20 min', '{"This is YOUR shot — own it","Set up with your feet first, then execute","Hit with authority — this is not practice, this is weapon building","Visualize using this shot in a match situation"}', '{"Player executes the weapon with quality 6 out of 10 times","Footwork and setup are consistent"}', '{"Not committing to the shot — going tentative","Poor setup — rushing the footwork","Not visualizing the match context"}', 'Play points where the player must set up and use their weapon.', 'Isolate the footwork pattern. Build the setup before adding the shot.', 'Weapon challenge — play a set where bonus points are awarded for executing the signature shot.', 'Every competitive player needs a weapon — a shot that opponents fear. Developing this weapon is what separates ASA players from lower levels.', null, null, null, 39) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('asa-liveball-1', 'Pattern Play — Serve + 1 + 2', '{"asa"}', 'liveball', 'tactical', 'live-ball', 'tactical', 'Extend the serve + 1 pattern to include a planned second shot. Build three-shot offensive sequences.', 'Player serves with a specific target. After the return, player executes a planned first ball (serve + 1). After the opponent''s response, player executes a planned second ball (serve + 2). Point is played out.', '20 min', '{"Plan three shots before you serve — serve, +1, +2","Each shot should set up the next one","If the pattern breaks, adapt — but start with the plan","Own the first three shots of the point"}', '{"Player executes the 3-shot pattern 3 out of 10 times","Serve placement consistently sets up the pattern"}', '{"No plan beyond the serve","Abandoning the pattern after the first shot","Not adapting when the opponent disrupts the pattern"}', 'Play full sets with serve + 1 + 2 as the tactical focus.', 'Focus on serve + 1 only. Add the second shot when the first pattern is consistent.', 'Pattern points — bonus point for completing the full 3-shot sequence.', 'At the ASA level, players must think in sequences, not individual shots. The serve + 1 + 2 is how elite players construct points from the service game.', null, null, null, 40) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('asa-serve-1', 'Serve Variation — First and Second Serve Packages', '{"asa"}', 'serve-return', 'serve-return', 'both', 'tactical', 'Develop serve packages — planned first and second serve combinations for different game situations.', 'Player serves sets of 10. Each set has a specific package: e.g., wide first serve + kick second serve to the body. Alternate packages.', '15 min', '{"Your first and second serve should work together as a package","If the first serve goes wide, the second serve should go to the body — keep them guessing","Vary your packages — don''t be predictable","Every serve must have a purpose"}', '{"Player executes 3 different serve packages consistently","First serve percentage above 55%","Second serve has visible spin and placement"}', '{"Same serve every time — no variation","Second serve is just a slower first serve","No tactical intent behind serve placement"}', 'Play points with specific serve packages assigned for each game.', 'Focus on one package at a time. Build consistency before adding variation.', 'Serve package challenge — coach calls the package before each point.', 'At the ASA level, the serve must be a weapon with variation. Predictable servers get broken. Varied servers hold serve and control matches.', null, null, null, 41) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('asa-points-1', 'Practice Sets — Match Simulation', '{"asa"}', 'points', 'tactical', 'live-ball', 'competitive', 'Full match simulation with tactical focus. Build the ability to execute game plans under real match pressure.', 'Players play full sets with proper scoring, changeovers, and warm up. Coach assigns a tactical focus for each player before the set.', '25-30 min', '{"Execute your game plan — don''t abandon it when you lose a few points","Use the changeover to assess and adjust","Compete on every point — this is your tournament preparation","Track your patterns — are you executing what you planned?"}', '{"Players execute their assigned tactical focus 50% of the time","Players demonstrate composure during changeovers","Players compete with full effort throughout"}', '{"Abandoning the game plan after falling behind","Not using changeovers productively","Emotional reactions that affect the next point"}', 'Play best of 3 sets. Add post-match analysis with the coach.', 'Play pro sets (first to 8). Coach provides tactical guidance at changeovers.', 'Consequence sets — loser does fitness. Winner earns a privilege.', 'Practice sets are the closest thing to real tournament play. Players who compete in practice compete in tournaments.', null, null, null, 42) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('fta-warmup-1', 'Match Intensity Warm Up — Point Simulation', '{"fta"}', 'warmup', 'baseline', 'live-ball', 'competitive', 'Warm up at match intensity from the first ball. Build the habit of competing from the moment you step on court.', 'Two players rally full court at 85-90% pace from the start. After 3 minutes, play 5 quick points. Then continue rallying at full intensity.', '10-12 min', '{"No casual warm ups at this level — compete from ball one","Find your rhythm quickly — you don''t get 20 minutes in a match","Move your feet and prepare early","Set the tone for the session with your intensity"}', '{"Players reach match pace within 2 minutes","Points are played with full competitive intent"}', '{"Starting too slowly — casual warm up habits","Not competing during the point play section","Poor footwork in the first few minutes"}', 'Start with serve and return warm up instead of rally.', 'Allow 5 minutes of gradual build before adding points.', 'Warm up points count — first to 3 wins.', 'FTA players must be ready to compete from the first point of a match. A slow start can cost you a set.', null, null, null, 43) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('fta-movement-1', 'Court Coverage Under Fatigue', '{"fta"}', 'movement', 'movement', 'feeding', 'technical', 'Build the ability to maintain court coverage and shot quality when fatigued. Develop physical and mental resilience.', 'Player completes a fitness circuit (sprints, shuffles, burpees) for 2 minutes, then immediately enters a 10-ball feeding pattern. Repeat 3 rounds.', '20 min', '{"Your technique should not change when you''re tired","Stay low — don''t stand up when fatigue hits","Breathe between shots — manage your energy","This is where matches are won — in the third set when everyone is tired"}', '{"Shot quality remains above 70% in fatigued rounds","Footwork patterns are maintained under fatigue"}', '{"Standing up and losing balance when tired","Shortening the swing under fatigue","Giving up on wide balls"}', 'Increase the fitness circuit intensity. Add more feeding balls.', 'Reduce the fitness circuit. Allow more recovery between rounds.', 'Fatigued points — play points immediately after the fitness circuit.', 'Matches are won in the later stages when both players are tired. The player who maintains technique and movement under fatigue wins.', null, null, null, 44) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('fta-feeding-1', 'Advanced Pattern Drilling — 4 Shot Sequences', '{"fta"}', 'feeding', 'tactical', 'feeding', 'tactical', 'Execute complex 4-shot tactical sequences with precision. Build the ability to construct points through planned patterns.', 'Coach feeds a sequence of 4 balls that simulate a specific tactical pattern (e.g., deep crosscourt, deep crosscourt, short angle, approach and volley). Player must execute all 4 shots with quality.', '20 min', '{"Think 4 shots ahead — not just the next ball","Each shot sets up the next one","Execute with precision — this is not about power, it''s about placement","Visualize the opponent''s position after each shot"}', '{"Player completes the 4-shot sequence with quality 4 out of 10 times","Shot placement is intentional on every ball"}', '{"Losing focus after the second shot","Not adjusting footwork for each shot in the sequence","Hitting with power instead of placement"}', 'Play points where the player must execute the 4-shot sequence to win.', 'Reduce to 3-shot sequences. Slower feeds.', 'Sequence challenge — bonus points for completing the full 4-shot pattern.', 'Elite players construct points through sequences, not individual shots. The ability to execute 4-shot patterns separates FTA players from the rest.', null, null, null, 45) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('fta-liveball-1', 'Tactical Match Play — Opponent Scouting', '{"fta"}', 'liveball', 'tactical', 'live-ball', 'tactical', 'Develop the ability to scout and adapt to an opponent''s game during live play. Build tactical awareness and adjustment skills.', 'Two players play a practice set. Before the set, each player is given a tactical brief about their opponent''s strengths and weaknesses. Players must adapt their game plan accordingly.', '25 min', '{"Study your opponent in the first 2 games — what are their patterns?","Adapt your game plan based on what you see","Exploit weaknesses — don''t just play your game, play against their game","Use the changeover to reassess and adjust"}', '{"Players demonstrate tactical adaptation within the first 3 games","Players can articulate their opponent''s patterns during changeovers"}', '{"Playing the same game regardless of the opponent","Not adjusting when the initial game plan isn''t working","Failing to identify opponent patterns"}', 'Add video review after the set. Analyze tactical decisions.', 'Coach provides tactical cues during changeovers.', 'Scouting challenge — after the set, each player must identify 3 patterns their opponent used.', 'At the FTA level, players must be able to scout and adapt during a match. The best players in the world adjust their game plan based on what they see across the net.', null, null, null, 46) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('fta-serve-1', 'Serve Under Pressure — Clutch Serving', '{"fta"}', 'serve-return', 'serve-return', 'both', 'competitive', 'Develop the ability to serve with quality under extreme pressure. Build mental toughness on the serve.', 'Player serves in pressure scenarios: 30-40, deuce, tiebreaker at 5-6. Must make the serve and execute the serve + 1 pattern. Consequences for double faults.', '15 min', '{"Trust your motion — don''t change anything under pressure","Breathe before the toss — slow everything down","Commit to the serve — no tentative swings","Your routine is your anchor — use it every time"}', '{"Player makes 80% of first serves in pressure scenarios","No more than 1 double fault per 10 pressure serves","Serve + 1 pattern is executed after successful serves"}', '{"Changing the serve motion under pressure","Rushing the routine","Double faulting on big points","Decelerating the swing"}', 'Add a crowd simulation — other players watch and react.', 'Start with less pressure scenarios (40-30, 40-15).', 'Clutch serve challenge — 10 pressure serves, must make 8 or fitness consequence.', 'The serve under pressure is what separates players who hold serve from players who get broken. FTA players must be clutch servers.', null, null, null, 47) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('fta-points-1', 'Tournament Simulation — Full Match with Analysis', '{"fta"}', 'points', 'tactical', 'live-ball', 'competitive', 'Full tournament-level match simulation with pre-match planning, in-match execution, and post-match analysis.', 'Players play a full best-of-3 set match with proper warm up, changeovers, and scoring. Coach observes and takes notes. Post-match analysis session follows.', '60-90 min', '{"Treat this exactly like a tournament match","Execute your pre-match game plan","Use changeovers to assess and adjust — write notes","Compete with full intensity from first point to last"}', '{"Players execute their game plan consistently","Players demonstrate tactical adaptation during the match","Players conduct themselves professionally throughout","Post-match analysis is specific and honest"}', '{"Not treating practice matches with tournament intensity","Failing to adjust when the game plan isn''t working","Poor body language affecting performance","Superficial post-match analysis"}', 'Add video analysis to the post-match review.', 'Play a pro set instead of best of 3. Coach provides guidance during changeovers.', 'Consequence match — results affect training group placement for the week.', 'This is the ultimate training tool for FTA players. Tournament simulation with analysis is how players prepare for real competition at the highest level.', null, null, null, 48) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('m-warmup-1', 'Mini Tennis — Continental Grip', '{"foundations","prep","jasa"}', 'warmup', 'baseline', 'live-ball', 'cooperative', 'Warm up hands, feel, and touch while reinforcing continental grip for volleys and slice.', 'Two players rally inside the service boxes using only continental grip. Focus on touch, feel, and control.', '5-8 min', '{"Continental grip only — no switching","Soft hands and short backswing","Control the ball, don''t hit through it","Move your feet — don''t reach"}', '{"Players sustain 10+ ball rallies in the service box","Continental grip is maintained throughout"}', '{"Switching to forehand grip","Hitting too hard — no control","Standing still instead of adjusting feet"}', 'Add volleys — one player at the net, one at the service line.', 'Allow any grip. Focus on rally consistency only.', 'First pair to 20 consecutive rallies wins.', 'Touch and feel are essential for net play, drop shots, and slice. Mini tennis develops these skills in a low-pressure setting.', null, null, null, 49) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('m-reflection-1', 'Session Reflection — 3 Takeaways', '{"foundations","prep","jasa","hs","asa","fta"}', 'reflection', 'mental', 'both', 'cooperative', 'Build self-analysis habits. Players identify what they learned, what they need to improve, and what they''ll focus on next.', 'Players sit in a circle or stand together. Each player shares: 1) One thing I did well, 2) One thing I need to work on, 3) One thing I''ll focus on next time.', '5 min', '{"Be specific — not just "I played well"","Be honest about what needs work","Listen when others share","This is how you get better — by thinking about your game"}', '{"Every player contributes","Reflections are specific and honest"}', '{"Generic answers — "I did good"","Not taking it seriously","Rushing through without real thought"}', 'Add journaling — players write their reflections in a notebook.', 'Coach prompts with specific questions.', 'Not applicable — reflection is cooperative by nature.', 'Self-analysis is what separates developing players from stagnant ones. The best players in the world reflect after every match.', null, null, null, 50) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('m-mental-1', 'Pressure Point — Must Win Scenarios', '{"jasa","hs","asa","fta"}', 'competitive-finish', 'mental', 'live-ball', 'competitive', 'Build mental toughness through must-win pressure scenarios. Develop composure and execution under stress.', 'Two players start a point at a critical score (e.g., 5-6, 30-40 on serve). Must win the point. Rotate scenarios.', '10 min', '{"Breathe before the point — control your nerves","Play your pattern — don''t panic","Trust your training — you''ve practiced this","Win or lose, reset immediately for the next scenario"}', '{"Players compete with composure in pressure scenarios","Players execute their patterns under pressure"}', '{"Rushing the point — trying to end it too quickly","Playing passively — not committing to shots","Emotional reaction after losing a pressure point"}', 'Add consequences — loser does fitness.', 'Start with less pressure scenarios. Build up gradually.', 'Pressure ladder — win 3 in a row to advance. Lose and start over.', 'Matches are decided in pressure moments. Players who practice these scenarios develop the composure to win tight matches.', null, null, null, 51) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('m-warmup-2', 'Dynamic Stretch & Movement Circuit', '{"prep","jasa","hs","asa","fta"}', 'warmup', 'physical', 'both', 'cooperative', 'Prepare the body for training through dynamic stretching and movement patterns. Reduce injury risk and improve readiness.', 'Players move through a circuit: high knees, butt kicks, lateral shuffles, carioca, walking lunges, leg swings, arm circles. 2 lengths of the court for each movement.', '8-10 min', '{"Full range of motion on every movement","Stay light on your feet","This is preparation, not a workout — controlled effort","Focus on the muscles you''ll use in training"}', '{"Players complete all movements with proper form","Players are visibly warm and ready after the circuit"}', '{"Rushing through movements","Half-effort on stretches","Skipping movements they don''t like"}', 'Add sport-specific movements — split steps, crossover steps, approach footwork.', 'Reduce the number of movements. Allow walking pace.', 'Not applicable — warm up is cooperative.', 'A proper dynamic warm up reduces injury risk and prepares the body for the demands of training and competition.', null, null, null, 52) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p2-prep-1', 'Crosscourt Rally with Target Zones', '{"prep"}', 'liveball', 'baseline', 'live-ball', 'tactical', 'Build crosscourt consistency and directional control with target zones.', 'Two players rally crosscourt. Cones mark a deep target zone in the last 4 feet of the court. Players must land 70% of shots in the zone.', '12 min', '{"Aim deep — the back fence is your friend","Use topspin to control depth","Recover to center after every shot","Extend through the hitting zone"}', '{"70% of shots land in the target zone","Rally length reaches 10+ balls consistently"}', '{"Balls landing in the service box","No directional intent","Flat shots without spin control"}', 'Add a change-direction rule after 8 balls.', 'Larger target zone. Cooperative pace only.', 'Any ball landing short of the service line loses the point.', 'Crosscourt depth is the foundation of rally control. Players who own the crosscourt rally own the baseline.', null, '{"Prep Orange Advanced","Prep Green Advanced"}', 'group', 53) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p2-prep-2', 'Serve and Return Placement Game', '{"prep"}', 'serve-return', 'serve-return', 'live-ball', 'tactical', 'Develop serve placement and return depth through structured target games.', 'Server aims for designated target (wide, body, T). Returner must land return past the service line. Play out the point after serve and return.', '12 min', '{"Serve with a plan — know your target before the toss","Return deep crosscourt as default","Recover after the serve","Use the return to neutralize, not attack"}', '{"Server hits target 5 out of 10 times","Returner lands deep 6 out of 10 times"}', '{"Serving without a target","Overhitting the return","No recovery after serve"}', 'Add serve + 1 pattern after placement.', 'Second serve only. Larger target zones.', 'Points for placement accuracy — 2 points for hitting the target zone.', 'Serve placement and return depth are the two most important shots in a match. They set the tone for every point.', null, '{"Prep Orange Advanced","Prep Green Advanced"}', 'group', 54) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p2-prep-3', 'Approach Shot and Volley Finish', '{"prep"}', 'liveball', 'transition', 'feeding', 'tactical', 'Build the approach-volley-finish sequence with proper footwork and net positioning.', 'Coach feeds a short ball. Player approaches deep to the open court, split steps at the service line, and finishes with a volley.', '12 min', '{"Move through the short ball — don''t stop","Approach deep and to the open court","Split step at the service line","Close the net after the first volley"}', '{"Player completes the full sequence 4 out of 10 times","Split step at the net is consistent"}', '{"Staying at the baseline after the approach","No split step before the volley","Approaching to the middle instead of the open court"}', 'Play out the point after the approach. Opponent can pass or lob.', 'Coach feeds the short ball directly. Remove the rally setup.', 'Bonus point for finishing at the net with a clean volley.', 'The approach-volley sequence is how players finish points at the net. It must be automatic.', null, '{"Prep Green Advanced"}', 'group', 55) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p2-prep-4', 'Two Ball Direction Change', '{"prep"}', 'feeding', 'baseline', 'feeding', 'technical', 'Develop the ability to change direction off a crosscourt ball. Build the footwork and timing to redirect.', 'Coach feeds two balls: first crosscourt, second to the middle. Player hits first ball crosscourt, then redirects the second ball down the line.', '12 min', '{"Set up early on the second ball","Use your feet to create the angle","Contact point must be in front for the redirect","Follow through toward your target"}', '{"Player redirects 5 out of 10 second balls to the target","Footwork adjustment is visible between shots"}', '{"Late setup on the second ball","Hitting both balls to the same spot","No footwork adjustment between shots"}', 'Add a third ball — play out the point after the redirect.', 'Slower feeds. Larger target zone for the redirect.', 'Points for accurate redirects — 2 points for hitting the target.', 'Changing direction is how players create openings. A player who can only hit crosscourt is predictable.', null, '{"Prep Orange Advanced","Prep Green Advanced"}', 'group', 56) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p2-prep-5', 'Short Ball Attack — Inside In and Inside Out', '{"prep"}', 'feeding', 'attacking', 'feeding', 'tactical', 'Teach players to recognize and attack short balls with inside-in and inside-out forehands.', 'Coach feeds short balls to the middle. Player must decide inside-in or inside-out and execute with depth and placement.', '12 min', '{"Read the short ball early","Move your feet to get around the ball","Hit with authority — this is your chance to attack","Aim deep, not just hard"}', '{"Player attacks 6 out of 10 short balls with depth","Decision between inside-in and inside-out is intentional"}', '{"Late recognition of the short ball","Hitting without moving feet","No directional intent — just hitting hard"}', 'Play out the point after the attack. Opponent can defend.', 'Predetermined direction. Slower feeds.', 'Attack challenge — points for depth and placement on short ball attacks.', 'Short ball attack is how points are won. Players who let short balls go are giving away free opportunities.', null, '{"Prep Green Advanced"}', 'group', 57) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p2-prep-6', 'Defensive Scramble and Reset', '{"prep"}', 'movement', 'defense', 'feeding', 'technical', 'Build defensive movement and the ability to reset the rally after being stretched wide.', 'Coach feeds wide balls that force the player to scramble. Player must get the ball back deep crosscourt and recover to center.', '10 min', '{"Get to the ball — no giving up","Hit high and deep to buy time","Recover to center immediately","Stay low through the recovery"}', '{"Player reaches 7 out of 10 wide balls","Recovery shot lands deep 60% of the time"}', '{"Giving up on wide balls","Hitting short after scrambling","Not recovering to center"}', 'Play out the point after the defensive shot.', 'Slower, less wide feeds. Focus on recovery footwork only.', 'Survival challenge — player must get 3 defensive balls back deep in a row.', 'Defense wins matches. Players who can scramble and reset keep themselves in points they should lose.', null, '{"Prep Green Advanced"}', 'group', 58) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p2-prep-7', 'First Strike Forehand', '{"prep"}', 'feeding', 'attacking', 'feeding', 'tactical', 'Develop an aggressive first-strike forehand off a short or mid-court ball.', 'Coach feeds a mid-court ball. Player steps in and drives a forehand with pace and depth to a target zone.', '10 min', '{"Step inside the baseline","Take the ball early — on the rise","Drive through the ball with intent","Aim deep to the target"}', '{"Player steps inside the baseline on 7 out of 10 feeds","First strike lands deep with pace 5 out of 10 times"}', '{"Waiting for the ball to come to them","Hitting from behind the baseline","No target — just hitting hard"}', 'Play out the point after the first strike.', 'Slower feeds. Larger target zone.', 'First strike points — bonus for winners off the first strike.', 'The first-strike forehand is how players take control of the rally early. Waiting gives the opponent time to set up.', null, '{"Prep Green Advanced"}', 'group', 59) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p2-prep-8', 'Topspin Lob Introduction', '{"prep"}', 'feeding', 'defense', 'feeding', 'technical', 'Introduce the topspin lob as a defensive and offensive tool against net players.', 'Coach or partner at the net. Player at the baseline hits topspin lobs over the net player, aiming to land deep in the court.', '10 min', '{"Brush up aggressively — more spin than pace","Aim high over the net player","Follow through high over your shoulder","Use when the opponent closes too tight"}', '{"Player lands 4 out of 10 lobs deep","Visible topspin on the lob"}', '{"Flat lob that sits up","Not enough height","No spin — just a moonball"}', 'Play out the point after the lob. Net player can try to recover.', 'Stationary net player. Focus on height and spin only.', 'Lob challenge — points for lobs that land in the last 3 feet.', 'The topspin lob is one of the most underused weapons in junior tennis. It punishes aggressive net closers and creates space.', null, '{"Prep Green Advanced"}', 'group', 60) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p2-prep-9', 'Serve Variation — Flat, Slice, Kick', '{"prep"}', 'serve-return', 'serve-return', 'both', 'technical', 'Introduce serve variation — flat, slice, and kick serves — with proper grip and contact point differences.', 'Player serves from the baseline. Coach assigns serve type for each set of 5: flat (power), slice (wide), kick (high bounce). Focus on grip and toss adjustment.', '12 min', '{"Flat — contact at the peak, straight through","Slice — brush the outside of the ball, toss slightly right","Kick — brush up the back of the ball, toss over your head","Each serve has a different toss position"}', '{"Player can identify and attempt all 3 serve types","Grip adjusts for each serve type"}', '{"Same toss for all serves","No grip change","Trying to hit too hard instead of focusing on spin"}', 'Serve games — player must use all 3 types in a service game.', 'Focus on one serve type per session.', 'Serve variety challenge — must use each type at least once in a tiebreaker.', 'Serve variation keeps the returner guessing. A predictable serve is an easy serve to return.', null, '{"Prep Green Advanced"}', 'group', 61) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p2-prep-10', 'Pressure Point Play — First to 3', '{"prep"}', 'points', 'pressure-match-prep', 'live-ball', 'competitive', 'Build competitive habits and pressure tolerance through short-format point play.', 'Players play first to 3 points with serve. Loser does 5 push-ups. Winner stays on. Rotate challengers.', '15 min', '{"Every point matters — no free points","Stick to your patterns under pressure","Reset between points — breathe","Compete with intensity, not emotion"}', '{"Players compete with visible intent","Patterns from training appear in point play"}', '{"Passive play under pressure","Emotional reactions after losing","Abandoning patterns"}', 'First to 5 with serve rotation.', 'First to 3 with coach feed to start.', 'This is already competitive. Add consequence for double faults.', 'Short-format pressure points simulate the intensity of close matches. Players who practice under pressure perform under pressure.', null, '{"Prep Orange Advanced","Prep Green Advanced"}', 'group', 62) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p2-jasa-11', 'Crosscourt to Down the Line Build', '{"jasa"}', 'liveball', 'baseline-pattern', 'live-ball', 'tactical', 'Develop the crosscourt-to-down-the-line pattern as a primary rally weapon.', 'Two players rally crosscourt. After 4 crosscourt balls, one player must change direction down the line. Point is live after the direction change.', '15 min', '{"Build the rally crosscourt first","Wait for the right ball to change direction","Down the line must be deep and with purpose","Recover after the direction change"}', '{"Direction change is intentional, not random","Down the line ball lands deep 60% of the time"}', '{"Changing direction too early","Down the line ball lands short","No recovery after the direction change"}', 'Play full points — must use the pattern to win.', 'Coach calls when to change direction.', 'Pattern points — bonus for winning with the crosscourt-to-DTL pattern.', 'The crosscourt-to-down-the-line build is the most fundamental rally pattern in tennis. It creates openings and forces errors.', null, '{"JASA UTR 1 to 2","JASA UTR 2 to 3"}', 'group', 63) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p2-jasa-12', 'Serve Plus One — Forehand Command', '{"jasa"}', 'serve-return', 'serve-plus-one', 'live-ball', 'tactical', 'Connect serve placement to the first groundstroke. Build the serve + 1 forehand as an offensive weapon.', 'Player serves to a target. After the return, player must hit a forehand (inside-out or inside-in) as the first groundstroke. Play out the point.', '15 min', '{"Serve with a plan — your serve sets up the forehand","Recover fast after the serve","First ball must be aggressive and intentional","Own the pattern — don''t react, execute"}', '{"Serve + 1 pattern is executed 4 out of 10 times","Serve placement supports the forehand setup"}', '{"Serving without a plan","Slow recovery after serve","First ball is passive instead of aggressive"}', 'Add serve + 1 + 2 — plan the first two groundstrokes.', 'Coach returns instead of partner. Predictable returns.', 'Serve + 1 points — extra point if the pattern is executed.', 'The serve + 1 forehand is the most important offensive sequence in tennis. It turns the serve into a weapon.', null, '{"JASA UTR 1 to 2","JASA UTR 2 to 3"}', 'group', 64) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p2-jasa-13', 'Return Plus One — Neutralize and Build', '{"jasa"}', 'serve-return', 'return-plus-one', 'live-ball', 'tactical', 'Develop the return + 1 pattern — neutralize with the return, then build with the next ball.', 'Partner serves. Returner hits deep crosscourt return, then plays the next ball with intent (change direction or attack). Play out the point.', '12 min', '{"Return deep crosscourt — neutralize first","Read the server''s next ball","Second ball should have more intent than the return","Don''t try to win on the return — win on the next ball"}', '{"Return lands deep 6 out of 10 times","Second ball has directional intent"}', '{"Overhitting the return","No plan for the second ball","Passive second ball after a good return"}', 'Add return + 1 + 2 — plan the first two shots after the return.', 'Second serve only. Focus on return depth.', 'Return + 1 points — bonus for executing the pattern.', 'The return + 1 is how players break serve. A deep return followed by an aggressive second ball puts the server under pressure.', null, '{"JASA UTR 1 to 2","JASA UTR 2 to 3"}', 'group', 65) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p2-jasa-14', 'Baseline Pattern — Wrong Foot', '{"jasa"}', 'liveball', 'baseline-pattern', 'live-ball', 'tactical', 'Teach the wrong-foot pattern — hitting behind the opponent after they commit to recovery.', 'Two players rally. One player must use the wrong-foot pattern at least once per point — hitting behind the opponent as they recover.', '12 min', '{"Watch the opponent''s recovery direction","Hit behind them as they move","Timing is everything — wait for the commitment","Use this when the opponent over-recovers"}', '{"Player identifies wrong-foot opportunities 3 out of 10 points","Wrong-foot shot is intentional, not accidental"}', '{"Hitting behind too early before the opponent commits","No awareness of opponent position","Using it randomly instead of reading the recovery"}', 'Play full sets — track wrong-foot winners.', 'Coach calls when to use the wrong-foot.', 'Wrong-foot bonus — double points for wrong-foot winners.', 'The wrong-foot is one of the most effective tactical patterns. It punishes predictable recovery and creates easy winners.', null, '{"JASA UTR 2 to 3"}', 'group', 66) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p2-jasa-15', 'Defensive Lob to Reset', '{"jasa"}', 'liveball', 'defense', 'live-ball', 'tactical', 'Build the defensive lob as a rally reset tool when under pressure.', 'One player attacks from inside the baseline. Defender must use a lob to push the attacker back and reset the rally. Point continues.', '10 min', '{"Lob high and deep — buy yourself time","Use topspin on the lob when possible","Recover to center after the lob","The lob is not giving up — it''s resetting"}', '{"Lob lands deep 5 out of 10 times","Player recovers to center after the lob"}', '{"Lob too short — easy overhead","No recovery after the lob","Using the lob as a panic shot instead of a tactical choice"}', 'Play out full points with lob as a required defensive option.', 'Coach feeds attacking balls. Focus on lob height and depth only.', 'Defender earns bonus point for lob that lands in the last 4 feet.', 'The defensive lob is an essential survival tool. It buys time, resets the rally, and frustrates aggressive opponents.', null, '{"JASA UTR 1 to 2","JASA UTR 2 to 3"}', 'group', 67) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p2-jasa-16', 'Open Court Finishing', '{"jasa"}', 'feeding', 'attacking', 'feeding', 'tactical', 'Develop the ability to finish points by hitting to the open court after creating an opening.', 'Coach feeds a sequence: first ball crosscourt (player hits), second ball to the middle (player redirects to the open court). Focus on recognizing and attacking the opening.', '12 min', '{"Read the open court before the ball arrives","Move your feet to create the angle","Hit with depth and placement, not just pace","Finish the pattern — don''t hesitate"}', '{"Player hits to the open court 5 out of 10 times","Finishing shot has depth and intent"}', '{"Hitting back to the opponent","No recognition of the open court","Hesitating on the finishing shot"}', 'Play out the point after the open court shot.', 'Coach points to the open court before the feed.', 'Open court points — bonus for finishing to the open side.', 'Finishing to the open court is how points are won. Players who create openings but don''t finish them waste their work.', null, '{"JASA UTR 2 to 3"}', 'group', 68) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p2-jasa-17', 'Transition Approach — Backhand Slice', '{"jasa"}', 'liveball', 'transition', 'feeding', 'tactical', 'Develop the backhand slice approach shot as a transition tool to the net.', 'Coach feeds a mid-court ball to the backhand. Player hits a deep slice approach and closes to the net for a volley finish.', '12 min', '{"Slice must stay low and deep","Move through the ball — don''t stop after the slice","Split step at the service line","Close the net for the volley"}', '{"Slice approach lands deep 5 out of 10 times","Player closes to the net after the approach"}', '{"Slice floats high","Stopping after the approach","No split step before the volley"}', 'Play out the point. Opponent can pass or lob.', 'Coach feeds directly to the backhand. Focus on slice depth only.', 'Approach points — bonus for finishing with a volley after the slice approach.', 'The backhand slice approach is one of the most reliable transition tools. It keeps the ball low and gives the approaching player time to close.', null, '{"JASA UTR 2 to 3"}', 'group', 69) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p2-jasa-18', 'Full Court Movement — Recovery and Reload', '{"jasa"}', 'movement', 'movement', 'feeding', 'technical', 'Build full court movement with emphasis on recovery position and reload between shots.', 'Coach feeds 8 balls in sequence covering all areas of the court. Player must execute each shot and recover to the optimal position before the next feed.', '15 min', '{"Split step before every ball","Recover to the correct position — not always center","Stay low through the recovery","Reload your stance before the next ball"}', '{"Player completes the 8-ball pattern with proper recovery","Recovery position is correct for the tactical situation"}', '{"Always recovering to dead center","Standing up between shots","No split step between balls"}', 'Increase feed pace. Add a 9th and 10th ball.', 'Reduce to 6 balls. Slower feeds with more recovery time.', 'Score each ball — 1 point for execution, 1 point for correct recovery position.', 'Recovery position is as important as the shot itself. Players who recover well are always in position for the next ball.', null, '{"JASA UTR 1 to 2","JASA UTR 2 to 3"}', 'group', 70) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p2-jasa-19', 'Competitive Tiebreaker with Patterns', '{"jasa"}', 'points', 'pressure-match-prep', 'live-ball', 'competitive', 'Build pressure tolerance and pattern execution in tiebreaker format.', 'Players play tiebreakers (first to 7, win by 2). Coach assigns a pattern that must be used on the first 2 points of each rotation.', '15 min', '{"Stick to the assigned pattern on the first 2 points","After that, play with intent — use what you''ve practiced","Reset between points — breathe","Compete with discipline, not emotion"}', '{"Assigned pattern is executed on the first 2 points","Players compete with composure throughout"}', '{"Abandoning the pattern under pressure","Emotional reactions","Passive play in the tiebreaker"}', 'Play best of 3 tiebreakers.', 'Start from 3-3 instead of 0-0.', 'This is already competitive. Add fitness consequence for the loser.', 'Tiebreakers are the highest-pressure situations in tennis. Players who practice them with patterns perform better under pressure.', null, '{"JASA UTR 1 to 2","JASA UTR 2 to 3"}', 'group', 71) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p2-jasa-20', 'Private Lesson — Weapon Building', '{"jasa"}', 'feeding', 'baseline', 'feeding', 'technical', 'Focused individual work on the player''s primary weapon — forehand or backhand — with high repetition and specific technical feedback.', 'Coach feeds 50+ balls to the player''s weapon side. Focus on specific technical elements: grip, contact point, extension, follow-through. Video analysis optional.', '20 min', '{"Focus on one technical element at a time","Quality over quantity — every rep matters","Feel the correct contact point","Build the muscle memory through repetition"}', '{"Player demonstrates improvement on the targeted technical element","Consistency improves over the session"}', '{"Trying to fix everything at once","Losing focus during high-rep feeding","Not transferring the correction to live ball"}', 'Add live ball application after the feeding block.', 'Reduce feed pace. Focus on shadow swings before hitting.', 'Target challenge — hit 10 in a row to the target zone.', 'Weapon development is the foundation of a player''s game style. Private lessons allow focused, individualized technical work that group sessions cannot provide.', null, '{"JASA UTR 1 to 2","JASA UTR 2 to 3"}', 'private', 72) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p2-asa-21', 'Serve Plus One Plus Two — Full Sequence', '{"asa"}', 'serve-return', 'serve-plus-one', 'live-ball', 'tactical', 'Develop the full serve + 1 + 2 offensive sequence. Build point construction from the serve.', 'Player serves to a target. After the return, player executes a planned 2-shot sequence (e.g., inside-out forehand then approach, or deep crosscourt then down the line). Play out the point.', '15 min', '{"Plan 3 shots before you serve","Serve placement must support the pattern","First ball aggressive, second ball finishing","Adjust if the return disrupts the plan"}', '{"Full 3-shot sequence executed 3 out of 10 times","Serve placement supports the pattern"}', '{"No plan beyond the serve","Slow recovery after serve","Abandoning the sequence after a difficult return"}', 'Play full service games with assigned sequences.', 'Coach returns. Predictable return direction.', 'Sequence points — bonus for completing the full 3-shot pattern.', 'The serve + 1 + 2 is how elite players construct service games. It turns the serve into a 3-shot weapon.', null, '{"ASA UTR 3 to 5","ASA UTR 5 to 7"}', 'group', 73) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p2-asa-22', 'Return Under Pressure — Second Serve Attack', '{"asa"}', 'serve-return', 'return', 'live-ball', 'tactical', 'Develop aggressive second serve return as a weapon. Build the ability to step in and attack.', 'Server hits second serves only. Returner must step inside the baseline and drive the return with depth and direction. Play out the point.', '12 min', '{"Step inside the baseline on second serves","Take the ball early — on the rise","Drive deep with intent — this is your chance to attack","Don''t give the server a free point on a weak second serve"}', '{"Returner steps inside the baseline 7 out of 10 times","Return lands deep with pace 5 out of 10 times"}', '{"Standing behind the baseline on second serves","Overhitting the return","No directional intent"}', 'Mix first and second serves. Returner must read and adjust.', 'Coach serves second serves. Focus on positioning only.', 'Return attack points — bonus for aggressive returns that land deep.', 'Attacking second serves is how players break serve at higher levels. A passive return gives the server control.', null, '{"ASA UTR 3 to 5","ASA UTR 5 to 7"}', 'group', 74) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p2-asa-23', 'Baseline Pattern — Heavy Crosscourt to Drop', '{"asa"}', 'liveball', 'baseline-pattern', 'live-ball', 'tactical', 'Develop the heavy crosscourt-to-drop shot pattern as a point construction tool.', 'Two players rally crosscourt with heavy topspin. After building pressure with depth, one player uses a drop shot to finish. Point is live after the drop.', '12 min', '{"Build pressure with heavy crosscourt first","The drop shot must be disguised — same preparation as a drive","Use the drop when the opponent is deep behind the baseline","Be ready for the response — close the net after the drop"}', '{"Drop shot is disguised 5 out of 10 times","Drop shot lands in the service box with low bounce"}', '{"Telegraphing the drop shot","Using the drop from a defensive position","Not closing the net after the drop"}', 'Play full points — must use the pattern to win.', 'Practice drop shot technique separately before adding to the pattern.', 'Pattern points — bonus for winning with the crosscourt-to-drop pattern.', 'The heavy crosscourt-to-drop pattern exploits opponents who sit deep. It changes the geometry of the point and forces them to move forward.', null, '{"ASA UTR 5 to 7","ASA UTR 7 to 10"}', 'group', 75) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p2-asa-24', 'Defensive Counterpunch — Absorb and Redirect', '{"asa"}', 'liveball', 'defense', 'live-ball', 'tactical', 'Build the ability to absorb pace and redirect with depth and direction under pressure.', 'One player attacks with pace. Defender must absorb the pace and redirect deep to a target zone. Point continues after the redirect.', '12 min', '{"Use the opponent''s pace — don''t add your own","Short backswing, firm wrist","Redirect deep crosscourt as default","Stay balanced through the contact"}', '{"Redirect lands deep 5 out of 10 times","Player maintains balance under pace"}', '{"Trying to match pace with pace","Long backswing against fast balls","Losing balance on contact"}', 'Defender must redirect and then attack on the next ball.', 'Slower attacking pace. Focus on redirect technique only.', 'Counterpunch points — defender earns bonus for redirect winners.', 'Counterpunching is an essential skill at higher levels. Players who can absorb and redirect turn defense into offense.', null, '{"ASA UTR 3 to 5","ASA UTR 5 to 7"}', 'group', 76) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p2-asa-25', 'Inside-Out to Inside-In Forehand Combo', '{"asa"}', 'feeding', 'attacking', 'feeding', 'tactical', 'Develop the inside-out to inside-in forehand combination as an offensive weapon.', 'Coach feeds to the backhand side. Player runs around and hits inside-out forehand, then coach feeds to the middle and player hits inside-in forehand. 2-ball combo.', '15 min', '{"First ball inside-out to push the opponent wide","Second ball inside-in to the open court","Move your feet early — get around both balls","Hit with authority on both shots"}', '{"Player executes the 2-ball combo 4 out of 10 times","Both shots have depth and direction"}', '{"Not getting around the second ball","Second ball going back inside-out","Losing balance on the footwork"}', 'Play out the point after the combo.', 'Practice each shot separately before combining.', 'Combo challenge — bonus for completing the full inside-out to inside-in sequence.', 'The inside-out to inside-in combo is one of the most devastating offensive patterns. It moves the opponent wide then attacks the open court.', null, '{"ASA UTR 5 to 7","ASA UTR 7 to 10"}', 'group', 77) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p2-asa-26', 'Net Closing — Volley to Volley Finish', '{"asa"}', 'liveball', 'transition', 'live-ball', 'tactical', 'Build the ability to close the net and finish with consecutive volleys.', 'Player approaches and hits first volley deep. Must close tighter to the net and finish with a second volley. Opponent can pass or lob.', '12 min', '{"First volley deep to set up the finish","Close the net after the first volley — don''t stay back","Second volley is the finishing shot — put it away","Stay compact — no big swings at the net"}', '{"Player closes after first volley 6 out of 10 times","Second volley is a clean finish 4 out of 10 times"}', '{"Staying at the service line after the first volley","Overswinging on the second volley","Not reading the opponent''s passing shot"}', 'Play full approach-volley-volley points.', 'Coach feeds the first volley. Focus on closing and finishing only.', 'Net closing points — bonus for finishing with 2 volleys.', 'Net closing is how players finish points efficiently. Two good volleys end the point faster than grinding from the baseline.', null, '{"ASA UTR 3 to 5","ASA UTR 5 to 7"}', 'group', 78) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p2-asa-27', 'Backhand Slice Variation — Low, Deep, Angle', '{"asa"}', 'feeding', 'baseline', 'feeding', 'technical', 'Develop three variations of the backhand slice: low and deep, short angle, and approach slice.', 'Coach feeds to the backhand. Player hits 5 of each variation: deep slice, short angle slice, and approach slice. Focus on racket face angle and follow-through differences.', '15 min', '{"Deep slice — follow through long and low","Angle slice — open the racket face and cut across","Approach slice — move through the ball, don''t stop","Same preparation for all three — disguise is key"}', '{"Player can execute all 3 variations","Disguise is consistent — same preparation"}', '{"Telegraphing the variation","Slice floating too high","No follow-through difference between variations"}', 'Play points where player must use all 3 slice variations.', 'Focus on one variation per round.', 'Slice variety challenge — coach calls the variation before each feed.', 'Slice variation keeps opponents off balance. A player with 3 different slices has 3 different tactical tools.', null, '{"ASA UTR 3 to 5","ASA UTR 5 to 7"}', 'group', 79) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p2-asa-28', 'Point Construction — 4 Ball Build', '{"asa"}', 'liveball', 'tactical', 'live-ball', 'tactical', 'Develop the ability to construct points through planned 4-ball sequences.', 'Two players rally. One player must execute a pre-assigned 4-ball pattern (e.g., deep CC, deep CC, short angle, DTL). Point is live throughout.', '15 min', '{"Think 4 shots ahead","Each shot sets up the next one","Execute with placement, not just power","Adjust the pattern if the opponent disrupts it"}', '{"Player completes the 4-ball pattern 3 out of 10 times","Each shot in the sequence has intent"}', '{"Losing the pattern after 2 shots","No adjustment when the opponent disrupts","Hitting with power instead of placement"}', 'Play full sets — must use the pattern at least once per game.', 'Reduce to 3-ball patterns.', 'Pattern points — bonus for completing the full 4-ball sequence.', 'Point construction through sequences is what separates tactical players from ball strikers. The ability to plan and execute 4-shot patterns wins matches.', null, '{"ASA UTR 5 to 7","ASA UTR 7 to 10"}', 'group', 80) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p2-asa-29', 'Match Play — Tactical Focus Sets', '{"asa"}', 'points', 'pressure-match-prep', 'live-ball', 'competitive', 'Full match simulation with assigned tactical focus. Build the ability to execute game plans under real pressure.', 'Players play pro sets (first to 8). Each player is assigned a tactical focus before the set (e.g., attack second serves, use drop shots, serve and volley on ad side).', '25 min', '{"Execute your tactical focus — don''t abandon it","Use changeovers to assess and adjust","Compete on every point","Track your pattern execution — how often are you using it?"}', '{"Tactical focus is executed 50% of the time","Players demonstrate composure during changeovers"}', '{"Abandoning the tactical focus when losing","Not using changeovers productively","Emotional reactions affecting the next point"}', 'Play best of 3 sets with tactical focus.', 'Coach provides tactical guidance at changeovers.', 'Consequence sets — loser does fitness.', 'Tactical focus sets teach players to execute game plans under pressure. This is exactly what happens in real tournament matches.', null, '{"ASA UTR 5 to 7","ASA UTR 7 to 10"}', 'group', 81) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p2-asa-30', 'Private Lesson — Serve Development Package', '{"asa"}', 'serve-return', 'serve-return', 'both', 'technical', 'Focused individual serve development — flat, slice, kick — with video analysis and high repetition.', 'Player serves 60+ balls across all 3 serve types. Coach provides real-time technical feedback. Video analysis of key serves. Focus on one improvement area per session.', '25 min', '{"One technical focus per session — don''t try to fix everything","Feel the difference between each serve type","Toss position is the key differentiator","Build consistency before adding pace"}', '{"Player shows measurable improvement on the targeted element","All 3 serve types are attempted with correct grip and toss"}', '{"Trying to fix everything at once","Losing focus during high-rep serving","Not adjusting toss for different serve types"}', 'Add serve + 1 patterns after the technical block.', 'Focus on one serve type only. Reduce to 30 serves.', 'Serve accuracy challenge — hit 5 in a row to each target zone.', 'The serve is the only shot you have complete control over. Private lesson serve development is the fastest way to improve it.', null, '{"ASA UTR 3 to 5","ASA UTR 5 to 7","ASA UTR 7 to 10"}', 'private', 82) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p2-fta-31', 'Serve Plus One — Kick Serve to Forehand Command', '{"fta"}', 'serve-return', 'serve-plus-one', 'live-ball', 'tactical', 'Connect the kick serve to a forehand command pattern. Build the serve + 1 as a structured offensive weapon.', 'Player serves a kick serve to the backhand. After the return, player runs around and hits an inside-out or inside-in forehand. Play out the point.', '15 min', '{"Kick serve must push the returner wide or high","Recover and set up the forehand early","First ball must be aggressive and deep","Own the geometry — your serve creates the opening"}', '{"Kick serve lands in the target zone 6 out of 10 times","Forehand command is executed 4 out of 10 times"}', '{"Kick serve landing short","Slow recovery after serve","Forehand going to the wrong target"}', 'Add serve + 1 + 2 — plan the first two groundstrokes.', 'Coach returns. Focus on serve placement only.', 'Serve + 1 points — bonus for completing the kick-to-forehand pattern.', 'The kick serve to forehand command is one of the most effective service patterns at the FTA level. It creates immediate offensive pressure.', null, '{"FTA UTR 5 to 8","FTA UTR 8 to 10"}', 'group', 83) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p2-fta-32', 'Return of Serve — Aggressive Positioning', '{"fta"}', 'serve-return', 'return', 'live-ball', 'tactical', 'Develop aggressive return positioning and the ability to take the ball early on both first and second serves.', 'Server serves full speed. Returner starts inside the baseline on second serves and at the baseline on first serves. Focus on early contact and depth.', '12 min', '{"Position aggressively — don''t give the server free space","Take the ball early — on the rise","Compact backswing — use the server''s pace","Return deep and with direction"}', '{"Returner positions correctly 8 out of 10 times","Return lands deep 6 out of 10 times"}', '{"Standing too far back","Long backswing against fast serves","No directional intent on the return"}', 'Play return games — returner must break serve.', 'Second serve only. Focus on positioning.', 'Return positioning points — bonus for returns from inside the baseline.', 'Aggressive return positioning puts immediate pressure on the server. It takes away time and forces the server to be more precise.', null, '{"FTA UTR 5 to 8","FTA UTR 8 to 10"}', 'group', 84) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p2-fta-33', 'Baseline Pattern — Heavy Ball to Short Angle', '{"fta"}', 'liveball', 'baseline-pattern', 'live-ball', 'tactical', 'Develop the heavy ball to short angle pattern as an advanced point construction tool.', 'Two players rally. One player must build with heavy topspin crosscourt, then use a short angle to pull the opponent off the court. Point is live.', '15 min', '{"Build pressure with heavy topspin first","The short angle must be disguised","Use the angle when the opponent is deep","Be ready to close the net after the angle"}', '{"Short angle is disguised 5 out of 10 times","Angle pulls the opponent outside the doubles alley"}', '{"Telegraphing the angle","Using the angle from a defensive position","Not following up after the angle"}', 'Play full sets — track angle winners.', 'Practice the angle shot separately before adding to the pattern.', 'Angle points — bonus for winning with the heavy-to-angle pattern.', 'The heavy ball to short angle is one of the most advanced patterns in tennis. It exploits deep positioning and creates impossible recovery angles.', null, '{"FTA UTR 8 to 10","FTA UTR 10 to 13"}', 'group', 85) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p2-fta-34', 'Defensive Reset — Slice and Lob Under Pressure', '{"fta"}', 'liveball', 'defense', 'live-ball', 'tactical', 'Build advanced defensive tools — deep slice and topspin lob — to reset rallies under extreme pressure.', 'One player attacks aggressively. Defender must use slice or topspin lob to reset the rally and survive. Point continues.', '12 min', '{"Slice deep to buy time","Topspin lob when the opponent closes the net","Choose the right tool for the situation","Recovery after the defensive shot is critical"}', '{"Defensive shot lands deep 5 out of 10 times","Player chooses the correct defensive tool"}', '{"Using the wrong defensive tool","Defensive shot landing short","No recovery after the defensive shot"}', 'Defender must reset and then counterattack on the next ball.', 'Slower attacking pace. Focus on one defensive tool at a time.', 'Survival points — defender earns bonus for resetting and winning the point.', 'Advanced defense is what keeps players in matches they should lose. The ability to reset under pressure is a championship skill.', null, '{"FTA UTR 5 to 8","FTA UTR 8 to 10"}', 'group', 86) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p2-fta-35', 'Attacking Transition — Approach and First Volley', '{"fta"}', 'liveball', 'transition', 'live-ball', 'tactical', 'Develop the attacking transition sequence with emphasis on first volley quality and net positioning.', 'Rally begins crosscourt. On a short ball, player approaches and must execute a quality first volley. Opponent can pass or lob. Play out the point.', '15 min', '{"Approach deep to the open court","Split step before the first volley","First volley deep — set up the finish","Close the net after the first volley"}', '{"First volley lands deep 5 out of 10 times","Player closes to the net after the first volley"}', '{"Approaching to the middle","No split step","First volley too short — easy pass"}', 'Play full points with mandatory approach on short balls.', 'Coach feeds the short ball. Focus on the approach and first volley only.', 'Transition points — bonus for finishing at the net.', 'The attacking transition is how complete players finish points. First volley quality determines whether the approach was worth it.', null, '{"FTA UTR 5 to 8","FTA UTR 8 to 10"}', 'group', 87) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p2-fta-36', 'Point Play — Serve and Volley Situations', '{"fta"}', 'points', 'point-play', 'live-ball', 'competitive', 'Develop serve and volley as a tactical option. Build the ability to close the net behind the serve.', 'Player must serve and volley on every point for one full game. Opponent plays normally. Focus on first volley depth and net positioning.', '15 min', '{"Serve and close — don''t hesitate","Split step at the service line","First volley deep to the open court","Close tighter after the first volley"}', '{"Player serves and volleys on every point","First volley lands deep 4 out of 10 times"}', '{"Hesitating after the serve","No split step","First volley too short"}', 'Play full sets with serve and volley on specific points (e.g., ad side only).', 'Second serve only. Focus on closing and first volley.', 'Serve and volley games — must serve and volley to hold serve.', 'Serve and volley is a valuable tactical weapon, especially on fast surfaces and in doubles. FTA players should have it in their toolbox.', null, '{"FTA UTR 8 to 10","FTA UTR 10 to 13"}', 'group', 88) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p2-fta-37', 'Physical — Court Coverage Under Extreme Fatigue', '{"fta"}', 'movement', 'physical', 'feeding', 'technical', 'Build the ability to maintain shot quality and movement patterns under extreme physical fatigue.', 'Player completes a high-intensity fitness circuit (suicides, burpees, sprints) for 3 minutes, then immediately enters a 12-ball feeding pattern. Repeat 4 rounds.', '25 min', '{"Your technique should not change when you''re dying","Stay low — fatigue makes you stand up","Breathe between shots — manage your energy","This is where championships are won"}', '{"Shot quality remains above 60% in fatigued rounds","Footwork patterns are maintained"}', '{"Standing up and losing balance","Shortening the swing","Giving up on wide balls"}', 'Play points immediately after the fitness circuit.', 'Reduce fitness circuit intensity. Allow more recovery.', 'Fatigued match play — play tiebreaker immediately after the circuit.', 'Third set tennis is won by the player who maintains technique under fatigue. This drill simulates the physical demands of a 3-set match.', null, '{"FTA UTR 8 to 10","FTA UTR 10 to 13"}', 'group', 89) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p2-fta-38', 'Mental — Pressure Serving Simulation', '{"fta"}', 'serve-return', 'pressure-match-prep', 'both', 'competitive', 'Build mental toughness on the serve through simulated high-pressure scenarios.', 'Player serves in pressure scenarios: 4-5 in the tiebreaker, 30-40 on serve, 5-6 in the set. Must make the serve and execute serve + 1. Other players watch.', '15 min', '{"Trust your routine — it''s your anchor","Breathe before the toss","Commit to the serve — no tentative swings","Block out the audience — focus on the process"}', '{"Player makes 75% of first serves under pressure","No more than 1 double fault per 10 pressure serves"}', '{"Changing the motion under pressure","Rushing the routine","Decelerating the swing"}', 'Add crowd noise and reactions.', 'Start with lower pressure scenarios.', 'Clutch serve challenge — 10 pressure serves, must make 7 or fitness consequence.', 'The serve under pressure is the most important mental skill in tennis. Players who can serve under pressure hold serve and win matches.', null, '{"FTA UTR 5 to 8","FTA UTR 8 to 10","FTA UTR 10 to 13"}', 'group', 90) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p2-fta-39', 'Tournament Simulation — Best of 3 with Scouting', '{"fta"}', 'points', 'pressure-match-prep', 'live-ball', 'competitive', 'Full tournament simulation with pre-match scouting, in-match adaptation, and post-match analysis.', 'Players play best of 3 sets. Before the match, each player receives a scouting report on their opponent. Must adapt game plan based on what they see. Post-match analysis with coach.', '90 min', '{"Study the scouting report — know your opponent","Adapt your game plan based on what you see in the first set","Use changeovers to reassess","Compete with full intensity from first point to last"}', '{"Players demonstrate tactical adaptation","Players can articulate their adjustments during changeovers","Post-match analysis is specific and honest"}', '{"Ignoring the scouting report","Not adjusting between sets","Poor body language affecting performance"}', 'Add video analysis to the post-match review.', 'Play a pro set. Coach provides guidance at changeovers.', 'Results affect training group placement.', 'This is the ultimate FTA training tool. Tournament simulation with scouting and analysis is how players prepare for real competition.', null, '{"FTA UTR 8 to 10","FTA UTR 10 to 13"}', 'group', 91) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p2-fta-40', 'Private Lesson — Game Style Development', '{"fta"}', 'feeding', 'tactical', 'feeding', 'tactical', 'Focused individual work on developing the player''s unique game style — identifying strengths, building weapons, and creating signature patterns.', 'Coach and player work on 2-3 signature patterns that fit the player''s game style. High repetition feeding with tactical discussion. Video analysis of patterns.', '30 min', '{"This is about YOUR game — what makes you dangerous?","Build patterns around your strengths","Every player needs 2-3 signature patterns they can execute under pressure","Quality over quantity — every rep matters"}', '{"Player can articulate their game style","Signature patterns are executed with consistency","Player shows ownership of their tactical identity"}', '{"Trying to play someone else''s game","No clear identity or game style","Patterns that don''t match the player''s strengths"}', 'Apply signature patterns in match play.', 'Identify strengths through video analysis before building patterns.', 'Pattern execution challenge — player must execute signature pattern 5 times in a practice set.', 'Game style development is the most important long-term investment for an FTA player. Players with a clear identity and signature patterns compete with confidence.', null, '{"FTA UTR 5 to 8","FTA UTR 8 to 10","FTA UTR 10 to 13"}', 'private', 92) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p2-dbl-41', 'Partner Call and Cover', '{"jasa"}', 'liveball', 'doubles', 'live-ball', 'cooperative', 'Build communication and simple partner spacing in doubles.', 'Start one up one back on both sides. Rally begins crosscourt. Teams must call every ball and recover together.', '10 min', '{"Call early","Move with partner","Protect middle","Recover after every contact"}', '{"Constant communication","No dead space through middle","Both players move after each shot"}', '{"Silence","Watching partner play","Both players drifting to same side"}', 'Allow one player to switch forward after short ball.', 'Keep pattern cooperative only.', 'Point only counts if both partners communicate.', 'Creates basic doubles awareness and team connection.', null, '{"JASA UTR 1 to 2","JASA UTR 2 to 3"}', 'group', 93) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p2-dbl-42', 'One Up One Back Shift Drill', '{"jasa"}', 'liveball', 'doubles', 'live-ball', 'tactical', 'Teach one up one back movement and court balancing.', 'One team starts one up one back. Opponents rally crosscourt. Net player shadows movement while baseline player covers behind.', '10 min', '{"Net player shades middle","Baseline partner shifts behind ball line","Team keeps shape","Talk through every adjustment"}', '{"No huge middle gaps","Both players shift with ball","Net player stays active"}', '{"Frozen net player","Baseline player too deep and too wide","No communication"}', 'Play live after 4 cooperative balls.', 'Coach pause and reset positioning.', 'Teams score bonus for correct movement on 3 consecutive balls.', 'Teaches court geometry in one up one back doubles.', null, '{"JASA UTR 2 to 3"}', 'group', 94) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p2-dbl-43', 'First Volley Lane', '{"jasa","asa"}', 'serve-return', 'doubles', 'live-ball', 'tactical', 'Teach simple first volley target discipline in doubles.', 'Server serves and closes. First volley must go through assigned lane. Point stops after first volley.', '10 min', '{"Close after serve","Volley through big target","Stay compact","Partner shifts behind volley line"}', '{"First volley lands in target lane","Server closes correctly","Team spacing remains connected"}', '{"Stopping after serve","Trying to do too much with first volley","Partner not adjusting"}', 'Play out point.', 'Coach feed first volley.', 'One point for serve plus clean first volley.', 'Builds reliable doubles first strike structure.', null, '{"JASA UTR 2 to 3","ASA UTR 3 to 5"}', 'group-or-private', 95) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p2-dbl-44', 'Middle Ball Ownership', '{"asa"}', 'liveball', 'doubles', 'live-ball', 'tactical', 'Teach who takes the middle ball and why.', 'Doubles points begin with crosscourt feed. Teams must call middle ball ownership clearly and continue live.', '12 min', '{"Call middle early","Stronger ball takes priority","Partner adjusts after call","Do not leave middle unattended"}', '{"Decisive middle ball calls","No hesitation errors","Partner movement supports call"}', '{"Both going","Neither going","Late calls"}', 'Add poach option.', 'Slower rally start.', 'Double points for middle ball winner after clear call.', 'Improves confidence and clarity in team decisions.', null, '{"ASA UTR 3 to 5","ASA UTR 5 to 7"}', 'group', 96) on conflict (id) do nothing;
