insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p5-lb-121', '1 Cross 1 Line Live Pattern', '{"jasa","asa"}', 'liveball', 'baseline-pattern', 'live-ball', 'tactical', 'Teach players to stabilize crosscourt first, then change direction with balance and intent on the next ball.', 'Live rally starts crosscourt. Designated player plays one crosscourt ball, then one down the line ball, repeating the pattern while partner keeps the rally neutral and live.', '10-12 min', '{"Crosscourt ball builds the point","Change line only from a strong base","Recover to the new geometry immediately","Do not overhit the line ball"}', '{"Player changes direction from balanced contact","Crosscourt ball has shape and depth","Recovery matches shot choice"}', '{"Changing line off a stretch ball","Flattening the line ball too early","Watching the shot instead of recovering"}', 'Play out the point live after every line change.', 'Coach feeds the first two balls before the live pattern starts.', 'Score only if the line change is made cleanly and the player wins the next neutral ball.', 'Builds the basic crosscourt-to-line pattern that shows up constantly in singles play.', null, '{"JASA UTR 2 to 3","ASA UTR 3 to 5"}', 'group-or-private', 173) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p5-lb-122', '2 Cross 1 Line Live Pattern', '{"jasa","asa","fta"}', 'liveball', 'baseline-pattern', 'live-ball', 'tactical', 'Build point construction discipline by using two crosscourt balls to move and organize before changing direction down the line.', 'Live crosscourt rally. Designated player must play two crosscourt balls before the third ball may be taken down the line. Opponent plays neutral live responses.', '12 min', '{"First two balls create shape and space","Earn the line change","Load outside leg before changing direction","Recover for the next pattern, not the winner"}', '{"Two crosscourt balls stay disciplined","Line change comes off the correct ball","Player maintains balance through the whole sequence"}', '{"Rushing the line change","Crosscourt balls too short","No recovery after the line ball"}', 'Play live with open scoring after the line change.', 'Feed the first crosscourt ball to give the player better spacing.', 'Line-change point only counts if both crosscourt balls hit target depth first.', 'Trains a dependable movement pattern for building an opening before changing direction.', null, '{"JASA UTR 2 to 3","ASA UTR 3 to 5","ASA UTR 5 to 7","FTA UTR 5 to 8"}', 'group-or-private', 174) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p5-lb-123', '3 Cross 1 Line Live Pattern', '{"asa","fta"}', 'liveball', 'baseline-pattern', 'live-ball', 'tactical', 'Train higher-level rally patience and court opening by requiring three disciplined crosscourt balls before the line release.', 'Live rally begins crosscourt. Player must hold three crosscourt balls with shape and depth before changing the fourth ball down the line.', '12-15 min', '{"Win the crosscourt exchange first","Stay heavy through the neutral phase","Recognize the green-light ball","Explode into the line change without losing shape"}', '{"Three crosscourt balls stay organized","Line change is decisive, not reckless","Recovery after the change is immediate"}', '{"Forcing the line too early","Losing discipline in the rally phase","Over-swinging on the release ball"}', 'Require the next ball after the line change to go back behind the opponent.', 'Reduce to 2 cross 1 line.', 'First player to complete three clean sequences wins.', 'Improves patience, rally tolerance, and direction change timing under live-ball pressure.', null, '{"ASA UTR 5 to 7","ASA UTR 7 to 10","FTA UTR 5 to 8","FTA UTR 8 to 10"}', 'group-or-private', 175) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p5-lb-124', 'Backhand 2 Cross 1 Line Pattern', '{"asa","fta"}', 'liveball', 'baseline-pattern', 'live-ball', 'tactical', 'Build trust in the backhand crosscourt exchange and improve the decision to release down the line from a strong ball.', 'Backhand-to-backhand live rally. Designated player must play two backhand crosscourt balls before changing the third down the line.', '10-12 min', '{"Trust backhand shape first","Hold posture through the crosscourt ball","Line change only from a strong contact window","Recover for the next forehand or backhand response"}', '{"Backhand remains stable through the pattern","Line change is made from correct spacing","Player keeps body line organized"}', '{"Flattening the backhand under pressure","Changing line off a weak ball","Poor recovery after release"}', 'Play out point only after the line change lands in target.', 'Coach feeds first backhand to establish spacing.', 'Complete five clean backhand sequences before switching roles.', 'Builds real backhand pattern trust instead of panic redirection.', null, '{"ASA UTR 3 to 5","ASA UTR 5 to 7","FTA UTR 5 to 8"}', 'group-or-private', 176) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p5-lb-125', 'Forehand Pattern Movement — Run Around and Recover', '{"asa","fta"}', 'liveball', 'attacking', 'live-ball', 'tactical', 'Train the movement required to run around the backhand, use the forehand as a weapon, and recover into the next pattern correctly.', 'Live rally starts neutral. Player is allowed to run around one backhand ball each sequence to play an inside-out or inside-in forehand, then must recover and continue the point live.', '12 min', '{"Run around with purpose, not panic","Choose the correct forehand target","Do not admire the forehand","Recovery must match the shot pattern"}', '{"Run-around decision is smart","Forehand target is clear","Player recovers into the next court position on time"}', '{"Running around the wrong ball","Leaving backhand side too open","Over-attacking the first forehand"}', 'Require player to finish with the next forehand if the first run-around creates space.', 'Use coach-fed entry ball before playing live.', 'Point counts double if the player executes run-around + recovery + next-ball pattern cleanly.', 'Builds a real weapon pattern instead of random forehand aggression.', null, '{"ASA UTR 5 to 7","ASA UTR 7 to 10","FTA UTR 5 to 8","FTA UTR 8 to 10"}', 'group-or-private', 177) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p5-lb-126', 'Line Change on Green Light', '{"jasa","asa","fta"}', 'liveball', 'tactical', 'live-ball', 'tactical', 'Improve recognition of the correct ball to change direction instead of changing line from poor court positions.', 'Players rally live crosscourt. Coach calls green light only when the incoming ball is strong enough to justify a line change. Player may only change line on the green light ball.', '10 min', '{"Recognize the right ball early","Line change needs base, shape, and space","Stay patient until the cue","Recover for the new pattern immediately"}', '{"Line changes happen only on correct ball","Player stays balanced on the change","Crosscourt discipline remains intact before the cue"}', '{"Changing line off a stretch ball","Overhitting once green light appears","Losing patience before the cue"}', 'Remove the coach cue and ask player to self-identify the green light ball.', 'Coach feeds a clearer shorter ball before allowing the line change.', 'Player loses point automatically for changing line without a green light.', 'Sharpens one of the hardest tactical decisions in singles — when to release down the line.', null, '{"JASA UTR 2 to 3","ASA UTR 3 to 5","ASA UTR 5 to 7","FTA UTR 5 to 8"}', 'group-or-private', 178) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p5-lb-127', 'Defend, Reset, Then Line', '{"asa","fta"}', 'liveball', 'defense', 'live-ball', 'tactical', 'Teach players to defend with shape, recover to neutral, and then change direction only after they have truly reset the rally.', 'Coach or partner starts by stretching the player wide. Player must defend high crosscourt, recover, play one neutral reset ball, then may change the next ball down the line if balanced.', '12 min', '{"First job is survival","Reset before you release","Use height to buy time","Line change happens after recovery, not during panic"}', '{"Defensive ball creates time","Neutral reset is organized","Line change comes from a balanced court position"}', '{"Trying to attack from defense","No real reset ball","Changing line while still outside the court"}', 'Play live with open scoring after the line change.', 'Use a less extreme starting defensive feed.', 'Player gets 2 points for a full defend-reset-line sequence executed cleanly.', 'Builds the movement and patience needed to turn defense back into neutral, then neutral into offense.', null, '{"ASA UTR 5 to 7","ASA UTR 7 to 10","FTA UTR 5 to 8","FTA UTR 8 to 10"}', 'group-or-private', 179) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p5-lb-128', 'Inside-Out Forehand Isolation Feed', '{"asa","fta"}', 'feeding', 'attacking', 'feeding', 'technical', 'Groove the footwork and spacing needed to run around the backhand and produce a repeatable inside-out forehand.', 'Coach feeds repeatable balls to the ad-side backhand corner. Player runs around and hits inside-out forehand crosscourt to a deep target.', '8-10 min', '{"Recognize early","Use the C-shape footwork","Create real space before contact","Land going through the target"}', '{"Player gets around the ball cleanly","Forehand target is crosscourt with shape","Recovery starts immediately after contact"}', '{"Crowding the ball","Running around the wrong feed","Opening shoulders too early"}', 'Add a recovery cone and live second ball.', 'Coach hand-feeds shorter and slower entry balls.', '10-ball inside-out target challenge.', 'Builds one of the most important forehand weapon patterns in competitive tennis.', null, '{"ASA UTR 3 to 5","ASA UTR 5 to 7","FTA UTR 5 to 8"}', 'group-or-private', 180) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p5-lb-129', 'Inside-Out to Inside-In Progression', '{"asa","fta"}', 'liveball', 'attacking', 'live-ball', 'tactical', 'Teach players to use inside-out forehands to open the court before releasing the next ball inside-in.', 'Player runs around first ball for inside-out forehand. If the reply stays neutral, player gets the next forehand and may go inside-in to the open court.', '10-12 min', '{"Inside-out opens, inside-in finishes","Do not force the second change","Feet must beat the ball","Recover after the first forehand with intent"}', '{"First forehand creates shape and width","Second forehand is chosen correctly","Player stays balanced on both direction changes"}', '{"Trying to finish too early","Poor first recovery","Inside-in ball flattened too much"}', 'Play full point with open scoring after the inside-in ball.', 'Coach guarantees a neutral second ball to simplify decision making.', 'Sequence only counts when both forehands hit their target zones.', 'Builds a true forehand one-two pattern instead of random aggression.', null, '{"ASA UTR 5 to 7","ASA UTR 7 to 10","FTA UTR 5 to 8","FTA UTR 8 to 10"}', 'group-or-private', 181) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p5-lb-130', 'Ad Corner Forehand ISO Ladder', '{"jasa","asa"}', 'feeding', 'attacking', 'feeding', 'technical', 'Improve the movement pattern for attacking forehands from the ad side with controlled depth and shape.', 'Coach feeds a ladder of balls from moderate to aggressive pace into the ad corner. Player moves around and drives forehands to deep deuce targets.', '8 min', '{"Set the feet before the swing","Use legs, not arm only","Choose shape first, pace second","Recover on the crossover"}', '{"Player organizes feet on every ball","Ball lands deep with shape","Recovery is consistent"}', '{"Reaching instead of spacing","Falling backward","Trying to hit winners on every rep"}', 'Add an approach option on short feed.', 'Use slower and shorter feeds.', 'Ladder must be completed without two misses in a row.', 'Builds confidence stepping around the backhand side under time pressure.', null, '{"JASA UTR 2 to 3","ASA UTR 3 to 5"}', 'group-or-private', 182) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p5-lb-131', 'Run-Around Forehand Decision Game', '{"asa","fta"}', 'liveball', 'attacking', 'both', 'tactical', 'Improve decision making on when to run around the backhand and when to stay honest and play the backhand.', 'Live neutral rally. Player may run around only balls that land in a designated green-light zone. Any run-around outside that zone loses the point.', '10 min', '{"Run around only when earned","Protect the open space you leave","Recover through the pattern","Do not chase forehands just because you like them"}', '{"Run-around choices are correct","Forehand target matches the situation","Player is not late recovering after the choice"}', '{"Overusing the run-around","Leaving too much court open","Running around defensive balls"}', 'Allow second attacking forehand after a good first run-around.', 'Make the green-light zone larger and clearer.', 'One point for correct choice, one point for clean execution.', 'Trains discipline around the forehand weapon instead of reckless forehand hunting.', null, '{"ASA UTR 5 to 7","ASA UTR 7 to 10","FTA UTR 5 to 8"}', 'group-or-private', 183) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p5-lb-132', 'Forehand ISO — Open Stance Reload', '{"jasa","asa"}', 'feeding', 'baseline', 'feeding', 'technical', 'Train players to load, hit, and reload quickly from repeated open-stance forehands under movement pressure.', 'Coach feeds repeated forehands to the same outside strike zone. Player must hit and recover to a marked reload spot every rep.', '8 min', '{"Sit into the outside leg","Hit up and through","Reload before the next feed","Do not stand up out of the shot"}', '{"Outside-leg load is visible","Recovery is repeatable","Depth stays stable under repetition"}', '{"Standing too tall","No reload habit","Arm-dominant forehand"}', 'Alternate higher and lower contact heights.', 'Increase time between feeds.', 'Must hit six clean forehands in a row before switching.', 'Improves repeated forehand movement and reload quality in live rallies.', null, '{"JASA UTR 1 to 2","JASA UTR 2 to 3","ASA UTR 3 to 5"}', 'group-or-private', 184) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p5-lb-133', 'Backhand Hold to Forehand Release', '{"asa","fta"}', 'liveball', 'baseline-pattern', 'live-ball', 'tactical', 'Build a disciplined backhand hold pattern that sets up a stronger forehand release ball later in the rally.', 'Player must hold two backhand crosscourt balls before stepping around the next forehand opportunity and attacking with inside-out or inside-in target.', '12 min', '{"Backhand holds the court","Do not rush the release ball","Forehand attack must come from a recovered position","Pattern before power"}', '{"Backhand phase is stable","Forehand release is chosen at the right moment","Player transitions cleanly between patterns"}', '{"Forcing forehand too early","Backhand phase too passive","Poor recovery before release"}', 'Play out the point with open scoring.', 'Coach cues when the release ball is available.', 'Two points for winning after a full backhand-hold forehand-release pattern.', 'Helps players connect their backhand stability to their forehand offense.', null, '{"ASA UTR 5 to 7","ASA UTR 7 to 10","FTA UTR 5 to 8"}', 'group-or-private', 185) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p5-lb-134', 'Two Ball Recover and Re-Load', '{"prep","jasa","asa"}', 'movement', 'movement', 'feeding', 'technical', 'Improve recovery mechanics by forcing players to hit, recover, then immediately reorganize for the next directional ball.', 'Coach alternates two feeds — one wider, one more central. Player must recover fully between contacts instead of sliding from shot to shot.', '8 min', '{"Recover all the way, not halfway","Prep again on second ball","Stay low through recovery","Feet organize before the swing"}', '{"Recovery is complete","Second-ball spacing is better than first-ball scramble","Player does not drift upright"}', '{"Lazy first recovery","Staying too open after contact","Late prep on second ball"}', 'Make second ball live after the feed.', 'Shorter movement distance.', 'Recovery lane challenge — miss the lane and rep does not count.', 'Builds the repeated reset habit needed for rally consistency.', null, '{"Prep Green Advanced","JASA UTR 1 to 2","ASA UTR 3 to 5"}', 'group-or-private', 186) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p5-lb-135', 'Three Ball Movement Wave', '{"jasa","asa"}', 'movement', 'movement', 'feeding', 'technical', 'Develop movement sequencing across three consecutive balls with different court positions.', 'Coach feeds one wider ball, one body ball, then one short-angle or shorter ball. Player must solve all three in sequence with organized footwork.', '10 min', '{"First move is decisive","Reset body between solves","Short ball requires forward transition","Do not let one bad movement wreck the sequence"}', '{"Player solves all three movement patterns with balance","Recovery habits are present between feeds","Contact quality holds through the sequence"}', '{"Overrunning the short ball","Staying too reactive after the first feed","Panic footwork on the third ball"}', 'Make the third ball live.', 'Use more predictable feed rhythm.', 'Complete four clean waves before rotating.', 'Reflects how movement rarely comes as one isolated ball in matches.', null, '{"JASA UTR 1 to 2","JASA UTR 2 to 3","ASA UTR 3 to 5"}', 'group-or-private', 187) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p5-lb-136', 'Inside-Out Crosscourt Live Rally', '{"asa","fta"}', 'liveball', 'attacking', 'live-ball', 'tactical', 'Build repeatable inside-out forehand patterning in a fully live crosscourt rally context.', 'Player starts neutral but must use the first clear ad-side forehand chance to run around and play inside-out. Opponent rallies live and tries to neutralize.', '10-12 min', '{"See the run-around early","Inside-out uses shape, not just pace","Recover through the deuce pattern","Do not leave ad side naked"}', '{"Inside-out ball opens the court effectively","Player recovers into the next geometry","Run-around decision is not forced"}', '{"Trying to create inside-out on every ball","No recovery after run-around","Ball travels too flat crosscourt"}', 'Require second attacking forehand after a strong inside-out.', 'Coach feeds the first ad-side entry ball.', 'Pattern point only counts if player wins after inside-out without cheap recovery error.', 'Directly builds a premium offensive forehand pattern used by stronger players.', null, '{"ASA UTR 5 to 7","ASA UTR 7 to 10","FTA UTR 5 to 8","FTA UTR 8 to 10"}', 'group-or-private', 188) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p5-lb-137', 'Inside-In Finish off the Short Ball', '{"asa","fta"}', 'liveball', 'attacking', 'both', 'tactical', 'Train the movement, spacing, and line commitment needed to finish inside-in off a true attackable ball.', 'Live rally until coach or opponent gives a clear shorter ad-side ball. Player must move forward, organize, and finish inside-in with margin.', '10 min', '{"Move forward through the short ball","Inside-in needs shape and target, not hero speed","Recover to net or next ball with intention","Do not hit inside-in from neutral depth"}', '{"Player attacks only the real short ball","Inside-in target is high percentage","Transition after attack is clear"}', '{"Forcing line from neutral court","Late feet on short ball","Standing still after the finish"}', 'Add mandatory first volley after the inside-in.', 'Coach hand-feeds the attack ball.', 'Inside-in winner or forced-error challenge.', 'Turns a short ball into a real finishing pattern instead of a rushed error.', null, '{"ASA UTR 5 to 7","ASA UTR 7 to 10","FTA UTR 8 to 10"}', 'group-or-private', 189) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p5-lb-138', 'Crosscourt Hold Under Movement', '{"prep","jasa","asa"}', 'liveball', 'baseline', 'live-ball', 'cooperative', 'Improve rally tolerance and footwork by requiring players to hold disciplined crosscourt shape while moving under pressure.', 'Cooperative live rally crosscourt only. Coach adds movement targets or wider feeds through live hand-feeds or partner pressure. Goal is shape plus movement quality.', '10 min', '{"Shape buys time","Feet organize every ball","Do not chase line changes","Recover to the right crosscourt position"}', '{"Rally stays organized under movement","Depth and shape remain stable","Player solves wide balls without panic"}', '{"Flattening under movement","No split step","Turning cooperative rally into ego hitting"}', 'Add a line change only after 8-ball rally count.', 'Reduce rally speed or use smaller court.', 'Highest honest crosscourt streak wins.', 'Strong live-ball movement starts with the ability to hold a crosscourt rally under stress.', null, '{"Prep Green Advanced","JASA UTR 1 to 2","JASA UTR 2 to 3","ASA UTR 3 to 5"}', 'group-or-private', 190) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p5-lb-139', 'Forehand Open-Court Chase', '{"asa","fta"}', 'liveball', 'attacking', 'live-ball', 'competitive', 'Train players to recognize the open court created by the forehand and then chase the next ball with aggressive movement.', 'Player uses forehand to open the court crosscourt, then must cover the likely reply and finish or build with the next forehand.', '10 min', '{"Open the court first","Expect the reply","Feet move before the ball crosses the net","Second forehand should be organized, not desperate"}', '{"First forehand creates clear space","Player reads and covers the likely reply","Second forehand keeps quality"}', '{"Watching the first forehand","Poor anticipation","Overhitting the follow-up ball"}', 'Play full point with open scoring.', 'Coach predetermines reply zone.', 'Two-ball forehand sequence challenge.', 'Builds the movement and anticipation needed after creating space with the forehand.', null, '{"ASA UTR 5 to 7","ASA UTR 7 to 10","FTA UTR 5 to 8","FTA UTR 8 to 10"}', 'group-or-private', 191) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p5-lb-140', 'Defend to Neutral Crossover Drill', '{"jasa","asa","fta"}', 'movement', 'defense', 'feeding', 'technical', 'Improve the crossover and recovery mechanics needed to get from defensive stretch position back to neutral court position.', 'Coach feeds a wider defensive ball first, then a neutral ball that must be played from a recovered position. Player repeats the crossover recovery pattern every rep.', '8 min', '{"First job is space and height","Cross over to recover, do not float back","Second ball must look neutral, not panicked","Recover behind the ball, not beside it"}', '{"Defensive ball buys time","Recovery footwork is efficient","Second contact is calmer and more organized"}', '{"Shuffle instead of crossover","No height on first defend","Late to the neutral second ball"}', 'Make the second ball live.', 'Reduce the width of the first defensive feed.', 'Streak of clean defend-neutral sequences.', 'Improves one of the most common movement patterns in real singles play.', null, '{"JASA UTR 2 to 3","ASA UTR 3 to 5","ASA UTR 5 to 7","FTA UTR 5 to 8"}', 'group-or-private', 192) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p5-lb-141', 'Forehand Recovery Figure 8', '{"jasa","asa"}', 'movement', 'movement', 'feeding', 'technical', 'Sharpen repeated forehand movement and recovery with a figure-8 pattern around center recovery markers.', 'Coach alternates two forehand feeds around center cones. Player moves in a figure-8 path, strikes, and recovers around the markers each rep.', '8 min', '{"Feet never stop after contact","Recover around the cone, not through it","Keep upper body calm while the feet work","Set the base before every forehand"}', '{"Recovery route is clean","Player stays balanced through repeated movement","Forehand quality does not drop late in the set"}', '{"Cutting the recovery line","Standing up between balls","Late setup on the second ball"}', 'Add one live decision ball after every figure-8 cycle.', 'Increase spacing and reduce feed speed.', 'Most clean figure-8 sequences in one minute.', 'Improves repeated forehand organization under movement load.', null, '{"JASA UTR 1 to 2","JASA UTR 2 to 3","ASA UTR 3 to 5"}', 'group-or-private', 193) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p5-lb-142', 'Backhand Line Change Release', '{"asa","fta"}', 'liveball', 'baseline-pattern', 'live-ball', 'tactical', 'Train players to release backhand down the line only after they have stabilized the crosscourt backhand exchange.', 'Backhand crosscourt live rally. Player may go down the line only after a target count or coach cue, then the point opens up live.', '10 min', '{"Backhand line needs strong base","Use the line release to change geometry, not just to hit harder","Recover for the forehand reply","Keep the crosscourt phase heavy and honest"}', '{"Crosscourt phase is stable","Backhand release lands with margin","Recovery after release is correct"}', '{"Line release too flat","No recovery after backhand line","Trying to change line from a weak contact point"}', 'Require next forehand to go behind the opponent.', 'Coach cues the release ball.', 'Line release only scores if the player wins within two more balls.', 'Builds trust in backhand direction changes instead of panic redirection.', null, '{"ASA UTR 5 to 7","ASA UTR 7 to 10","FTA UTR 5 to 8"}', 'group-or-private', 194) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p5-lb-143', 'Two Forehands Then Recover', '{"asa","fta"}', 'liveball', 'attacking', 'both', 'tactical', 'Build the ability to handle two aggressive forehands in sequence without losing court balance or recovery discipline.', 'Coach or partner gives player two forehand opportunities in sequence. Player attacks both with clear targets, then must recover into neutral before the point continues.', '10 min', '{"First forehand creates, second forehand finishes or builds","Do not fall in love with the second ball","Recovery after two attacks matters","Feet stay active between forehands"}', '{"Both forehands are organized","Targets are smart","Recovery after second forehand is immediate"}', '{"All-out swing on first ball","No spacing on second forehand","Watching the second ball instead of recovering"}', 'Open the point fully after the second forehand.', 'Use coach-fed second forehand.', 'Two-forehand clean sequence challenge.', 'Helps stronger players chain forehand offense without losing court position.', null, '{"ASA UTR 5 to 7","ASA UTR 7 to 10","FTA UTR 5 to 8","FTA UTR 8 to 10"}', 'group-or-private', 195) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p5-lb-144', 'Crosscourt Lock Then Approach', '{"jasa","asa","fta"}', 'liveball', 'transition', 'live-ball', 'tactical', 'Teach players to lock the rally crosscourt first, then transition forward only when they have created the right short ball.', 'Crosscourt live rally. Player must hold a target count crosscourt before approaching on a shorter neutral ball and finishing forward.', '12 min', '{"Crosscourt creates the approach","Do not force the transition","Approach with margin and purpose","First step forward must be aggressive"}', '{"Crosscourt phase is disciplined","Approach shot comes off the correct ball","Player closes with urgency"}', '{"Approaching too early","Weak transition footwork","No commitment after approach"}', 'Play full point out after approach.', 'Shorter crosscourt count before approach is allowed.', 'Approach sequence only scores if the first volley or next ball is organized.', 'Builds smarter transition play instead of random rushing to net.', null, '{"JASA UTR 2 to 3","ASA UTR 3 to 5","ASA UTR 5 to 7","FTA UTR 5 to 8"}', 'group-or-private', 196) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p5-lb-145', 'Middle Ball Recover and Redirect', '{"jasa","asa"}', 'liveball', 'tactical', 'live-ball', 'tactical', 'Improve the handling of middle balls by teaching players to recover, organize, and redirect rather than getting jammed.', 'Live rally with coach or partner feeding repeated middle balls after wider exchanges. Player must recover, create space, and redirect to the correct target.', '10 min', '{"Middle ball is a movement problem first","Create space before redirecting","Use shape under pressure","Do not get stuck on top of the ball"}', '{"Player creates spacing on the middle ball","Redirect target is clear and repeatable","Recovery is better after the redirect"}', '{"Jammed contact","Backing away from the ball","Trying to crush the redirect"}', 'Add line-change requirement after every second middle-ball solve.', 'Reduce the pace of the middle-ball feed.', 'Middle-ball solve streak challenge.', 'A lot of rally errors happen on middle balls, not just wide balls.', null, '{"JASA UTR 1 to 2","JASA UTR 2 to 3","ASA UTR 3 to 5"}', 'group-or-private', 197) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p5-lb-146', 'Forehand Trap and Release', '{"asa","fta"}', 'liveball', 'attacking', 'live-ball', 'tactical', 'Teach players to trap the opponent with repeated heavy forehands before releasing into the open court.', 'Player uses two or three heavy forehands to the same pattern target before releasing the next forehand to the open court when balance and court position allow.', '12 min', '{"Trap first, release second","Heavy ball must still recover","Release only when the opponent is stretched","Do not speed up too early"}', '{"Trap phase moves opponent consistently","Release ball is chosen from correct position","Player stays balanced through the whole sequence"}', '{"Trying to release too soon","Trap ball too light or too short","Poor recovery between heavy forehands"}', 'Require a finish at net after the release.', 'Reduce trap count to two balls.', 'Sequence counts only if opponent is visibly moved before release.', 'Builds a mature forehand pattern instead of one-ball hero tennis.', null, '{"ASA UTR 5 to 7","ASA UTR 7 to 10","FTA UTR 8 to 10","FTA UTR 10 to 13"}', 'group-or-private', 198) on conflict (id) do nothing;
insert into public.drills (id, name, level, session_block, skill_category, feeding_style, type, objective, setup, recommended_time, coaching_cues, standards, common_breakdowns, progression, regression, competitive_variation, match_play_relevance, video_url, sub_band, format, sort_order) values ('p5-lb-147', 'Live Ball Four-Corner Movement Pattern', '{"asa","fta"}', 'liveball', 'movement', 'both', 'competitive', 'Train players to solve front-back and side-to-side movement in one live-ball sequence without losing tactical intention.', 'Coach or partner creates a four-corner pattern: deep wide, shorter middle, opposite corner, then recovery ball. Player must solve all four and continue the point live.', '12-15 min', '{"Every ball needs a fresh solve","Do not carry one movement mistake into the next ball","Balance beats panic speed","Recover with purpose after every contact"}', '{"Player solves all four movement demands with quality","Recovery habits stay present under fatigue","Ball quality does not collapse late in the sequence"}', '{"Getting stuck after the short ball","Poor directional recovery","Technique falling apart under fatigue"}', 'Play live open point after the fourth ball.', 'Use a more predictable corner sequence.', 'Team race — most clean four-corner sequences in a set time.', 'Simulates the chaotic movement demands of real competitive points.', null, '{"ASA UTR 5 to 7","ASA UTR 7 to 10","FTA UTR 5 to 8","FTA UTR 8 to 10"}', 'group-or-private', 199) on conflict (id) do nothing;
insert into public.session_plans (id, plan_number, name, level_tag, level, sub_band, total_time, objective, blocks, coaching_emphasis, standards, common_mistakes, match_play_transfer, sort_order) values ('sp-f1', -4, 'Red Ball Athletic Foundations', 'Foundations Red Ball', 'foundations', 'Red Ball', 60, 'Build athletic literacy, coordination, and early tennis habits through structured movement and ball-tracking activities', '[{"label":"Warm Up","content":"Animal walks, skipping, hopping, agility ladder basics"},{"label":"Movement","content":"Cone touch relay, shuffle and split step intro"},{"label":"Main Drill 1","content":"Throw Catch Rally — forehand side focus"},{"label":"Main Drill 2","content":"Bounce Hit Counting Game — tracking and timing"},{"label":"Serve & Return","content":"Underhand toss to target zones"},{"label":"Point Play","content":"King of the Court mini — cooperative rally to 4 then play"},{"label":"Reflection","content":"One thing I did well, one thing to work on"}]'::jsonb, 'Fun with structure — every activity has a purpose', '{"Listening","Effort","Basic ready position","Tracking the ball"}', '{"Making it purely recreational with no standards","Skipping movement for stroke technique","Not coaching effort and behavior"}', 'Builds the athletic base and focus habits that all future tennis development depends on', 1) on conflict (id) do nothing;
insert into public.session_plans (id, plan_number, name, level_tag, level, sub_band, total_time, objective, blocks, coaching_emphasis, standards, common_mistakes, match_play_transfer, sort_order) values ('sp-f2', -3, 'Red Ball Movement and Rhythm', 'Foundations Red Ball', 'foundations', 'Red Ball', 60, 'Develop rhythm, balance, and early rally consistency through movement-first activities', '[{"label":"Warm Up","content":"Jump rope basics, balance beam walk, dynamic stretching"},{"label":"Movement","content":"Mirror drill with partner, reaction ball catches"},{"label":"Main Drill 1","content":"Rally Rhythm Counter — sustain rally with counting"},{"label":"Main Drill 2","content":"Forehand and Backhand Shape Intro — focus on contact point"},{"label":"Serve & Return","content":"Drop and hit to large target area"},{"label":"Point Play","content":"Cooperative rally then compete — rally 3 then play out"},{"label":"Reflection","content":"Coach-led group circle"}]'::jsonb, 'Rhythm and balance before power — move your feet first', '{"Feet moving before contact","Eyes on ball","Ready position between shots"}', '{"Letting players stand still and swing","No structure to rally activities","Ignoring effort and attitude"}', 'Builds the movement rhythm that makes rallying and point play possible', 2) on conflict (id) do nothing;
insert into public.session_plans (id, plan_number, name, level_tag, level, sub_band, total_time, objective, blocks, coaching_emphasis, standards, common_mistakes, match_play_transfer, sort_order) values ('sp-f3', -2, 'Red Ball Rally and Direction', 'Foundations Red Ball', 'foundations', 'Red Ball', 60, 'Introduce directional awareness and simple rally patterns on the red ball court', '[{"label":"Warm Up","content":"Tag games with movement patterns, dynamic warm up"},{"label":"Movement","content":"Cone gates — move through gates between shots"},{"label":"Main Drill 1","content":"Crosscourt Rally Challenge — hit to the same side"},{"label":"Main Drill 2","content":"Target Zones — coach feeds, player aims for colored zones"},{"label":"Serve & Return","content":"Toss to target with step in"},{"label":"Point Play","content":"Red ball singles — first to 7 with cooperative start"},{"label":"Reflection","content":"What direction did you hit most today?"}]'::jsonb, 'Direction awareness — know where you are hitting and why', '{"Aiming with intention","Recovery to ready position","Consistent effort"}', '{"Random hitting with no target","Skipping recovery between shots","Not enough reps"}', 'Players begin to understand that direction matters in points', 3) on conflict (id) do nothing;
