insert into public.assessments (stage_id, stage_name, categories, sort_order) values ('foundations', 'Red Ball', '[{"name":"Physical Literacy","standards":["Demonstrates basic balance on one foot","Can catch and throw with reasonable accuracy","Shows coordination in basic movement patterns","Maintains effort through full session"]},{"name":"Footwork","standards":["Moves to the ball with basic readiness","Attempts split step with coaching cue","Shows basic recovery toward center"]},{"name":"Baseline","standards":["Demonstrates basic unit turn","Can rally to the center consistently","Uses correct grip with reminders","Makes contact in front of the body"]},{"name":"Transition & Net Play","standards":["Can execute simple volleys at the net","Understands basic net positioning","Shows willingness to come forward"]},{"name":"Serve & Return","standards":["Can execute basic serve motion","Toss is reasonably consistent","Returns balls into play"]},{"name":"Character","standards":["Listens to coach instructions","Shows respect for coaches and other players","Demonstrates effort and willingness to try","Handles mistakes without major disruption"]},{"name":"Competition","standards":["Understands basic scoring","Can play simple points","Shows awareness of the court boundaries"]}]'::jsonb, 1);
insert into public.assessments (stage_id, stage_name, categories, sort_order) values ('foundations', 'Orange Ball', '[{"name":"Physical Literacy","standards":["Improved balance and coordination","Can perform basic athletic movements (shuffles, crossovers)","Shows rhythm in movement patterns","Maintains effort and focus through longer sessions"]},{"name":"Footwork","standards":["Consistent split step habit","Recovery to center after shots","Crossover movement developing","Adjusts feet to the ball before swinging"]},{"name":"Baseline","standards":["Unit turn is becoming habitual","Topspin basics are developing","Directional rallying (crosscourt and down the line)","Contact point is more consistent"]},{"name":"Transition & Net Play","standards":["Continental grip developing on volleys","Overhead basics are in place","Can execute approach and volley sequence"]},{"name":"Serve & Return","standards":["Continental grip on serve is developing","Toss and smooth motion improving","Basic placement awareness","Returns with direction"]},{"name":"Character","standards":["Problem solving on court","Shows independence in training","Handles competition with composure","Supports teammates and training partners"]},{"name":"Competition","standards":["Participates in Orange Ball tournaments","Understands match play format","Competes with effort regardless of score"]}]'::jsonb, 2);
insert into public.assessments (stage_id, stage_name, categories, sort_order) values ('prep', 'Green Ball', '[{"name":"Physical Literacy","standards":["Advanced coordination and athletic literacy","Can perform multi-directional movements fluidly","Balance maintained during shot execution","Endurance for longer training sessions"]},{"name":"Footwork","standards":["Split step timing is consistent","Deeper court coverage with proper recovery","Open stance developing on groundstrokes","Movement in multiple directions is fluid"]},{"name":"Baseline","standards":["Grip changes between forehand and backhand","Better contact points with consistency","Playing on the rise developing","Changing direction with intent","Exploiting opponent weaknesses"]},{"name":"Transition & Net Play","standards":["Transition patterns developing","Overhead accuracy improving","Approach shot to volley sequence","Net positioning awareness"]},{"name":"Serve & Return","standards":["Serve placement to specific zones","Leg drive developing in serve","Tactical serving concepts emerging","Return with depth and direction"]},{"name":"Character","standards":["Emotional control in competition","Takes ownership of effort and attitude","Shows resilience after setbacks","Communicates respectfully with partners"]},{"name":"Competition","standards":["Regular Green Ball tournament participation","Competitive habits developing","Doubles basics understood","Competes with patterns and intent"]}]'::jsonb, 3);
insert into public.assessments (stage_id, stage_name, categories, sort_order) values ('jasa', 'JASA', '[{"name":"Physical Literacy","standards":["Strong athletic base for full court play","Wider lower base in ready position","Deeper movement patterns","Physical endurance for extended play"]},{"name":"Footwork","standards":["Full court movement with efficient recovery","Split step is automatic","Can cover the full court and recover","Movement supports tactical execution"]},{"name":"Baseline","standards":["Full court pace and depth","Extension through the hitting zone","Tactical use of the forehand","Open court patterns developing","Consistency under pace"]},{"name":"Transition & Net Play","standards":["Transition competence — approach, volley, overhead","Attacking short balls with intent","Net play is a weapon, not a weakness","Closing patterns developing"]},{"name":"Serve & Return","standards":["Serve targets with consistency","More compact return technique","Serve + 1 pattern developing","Return with tactical intent"]},{"name":"Character","standards":["Independence in training and competition","Resilience under pressure","Self-analysis habits developing","Accountability for effort and attitude","Professional conduct on court"]},{"name":"Competition","standards":["UTR readiness","Regular yellow ball tournament play","Competes with intent and learns from results","Match play habits are developing"]}]'::jsonb, 4);
insert into public.assessments (stage_id, stage_name, categories, sort_order) values ('hs', 'HS', '[{"name":"Physical Literacy","standards":["Match-level fitness and endurance","Can sustain intensity through a full dual match","Athletic movement patterns are automatic","Injury prevention awareness and habits"]},{"name":"Footwork","standards":["Efficient court coverage in singles and doubles","Recovery patterns are automatic","Footwork supports shot variety and placement","Movement under pressure is consistent"]},{"name":"Baseline","standards":["Consistent groundstrokes under pace","Directional control with intent","Can sustain rallies and build points","Shot selection matches the tactical situation"]},{"name":"Transition & Net Play","standards":["Comfortable at the net in both singles and doubles","Approach and volley sequence is reliable","Overhead is a weapon, not a liability","Doubles net play is active and aggressive"]},{"name":"Serve & Return","standards":["Reliable first and second serve","Spin variation on second serve","Return neutralizes the server","Serve placement matches the tactical plan"]},{"name":"Character","standards":["Leadership on and off the court","Represents the team and program with professionalism","Supports teammates regardless of personal results","Handles adversity with composure and maturity"]},{"name":"Competition","standards":["Competes with full effort in team and individual matches","Understands dual match strategy and team dynamics","Performs under pressure in close matches","Demonstrates sportsmanship and respect for opponents"]}]'::jsonb, 5);
insert into public.assessments (stage_id, stage_name, categories, sort_order) values ('asa', 'ASA', '[{"name":"Physical Literacy","standards":["High-level athletic conditioning through APL","Strength and speed support on-court performance","Endurance for extended matches and training sessions","Recovery habits are established and consistent"]},{"name":"Footwork","standards":["Elite court coverage — can defend and attack from any position","Footwork patterns are automatic and efficient","Movement supports weapon execution","Can maintain footwork quality under fatigue"]},{"name":"Baseline","standards":["Weapon-level groundstroke on at least one side","Can construct points through patterns","Consistency under high pace and pressure","Directional control with depth and spin variation"]},{"name":"Transition & Net Play","standards":["Transition game is a reliable offensive tool","Can finish points at the net consistently","Approach shot selection is tactical and intentional","Comfortable in all net play situations"]},{"name":"Serve & Return","standards":["Serve is a weapon with variation and placement","Second serve has reliable spin and depth","Return can neutralize and attack","Serve + 1 patterns are consistent"]},{"name":"Character","standards":["Full accountability for training and competition","Professional conduct at all times","Self-analysis is specific and actionable","Resilience under pressure is demonstrated consistently","Commitment to the development process is unwavering"]},{"name":"Competition","standards":["Strong tournament schedule with clear goals","UTR is tracked and progressing","Competes with tactical intent and adapts during matches","Results reflect the quality of training"]}]'::jsonb, 6);
insert into public.assessments (stage_id, stage_name, categories, sort_order) values ('fta', 'FTA', '[{"name":"Physical Literacy","standards":["Elite athletic conditioning — strength, speed, endurance, flexibility","Physical training is fully integrated with on-court development","Nutrition and recovery are part of the daily routine","Body management and injury prevention are prioritized"]},{"name":"Footwork","standards":["World-class court coverage and movement efficiency","Footwork supports all tactical situations — offense, defense, transition","Movement quality is maintained in the third set under fatigue","Anticipation and positioning reduce the need for emergency movement"]},{"name":"Baseline","standards":["Multiple weapons from the baseline","Can construct and execute complex point patterns","Adapts game style based on opponent analysis","Consistency and aggression are balanced at the highest level"]},{"name":"Transition & Net Play","standards":["Complete net game — approach, volley, overhead, half-volley","Transition is a primary offensive strategy","Can finish points efficiently at the net","Net play decisions are tactically sound"]},{"name":"Serve & Return","standards":["Serve is a primary weapon with full variation","Can hold serve against high-level opponents","Return is a weapon that creates break opportunities","Serve and return patterns are planned and executed"]},{"name":"Character","standards":["Exemplary professionalism and leadership","Sets the standard for the entire program","Self-analysis is deep, honest, and drives improvement","Handles all competitive situations with composure","Commitment to excellence is visible in every interaction"]},{"name":"Competition","standards":["Full competitive schedule aligned with recruitment or elite goals","Competes nationally with measurable outcomes","Match play demonstrates tactical sophistication","Results reflect sustained commitment to the development process"]}]'::jsonb, 7);
insert into public.coach_standards (category, items, sort_order) values ('Tier 1 Coach Mantra', '{"Arrive early and prepared","Set the tone with energy, voice, presence, and clarity","Be fully present and not distracted","Coach every rep, not just feed balls","Give immediate and specific feedback","Hold players accountable without losing care","Build trust with players, parents, and staff","Make every player feel seen, not just the best player","Protect standards every day","Finish sessions with purpose and clear takeaways"}', 1);
insert into public.coach_standards (category, items, sort_order) values ('Professional Expectations', '{"Coaches must be on time and prepared","Sessions must align with Tier 1 training standards","Phone use should be extremely limited during sessions","Coaches must present professionally on court","Safety and athlete engagement matter at all times","Coaches are expected to communicate professionally with families and staff"}', 2);
insert into public.coach_standards (category, items, sort_order) values ('Presence & Authority', '{"Set the tone from the moment players arrive","Use your voice — project, don''t mumble","Position yourself where you can see all players","Move with purpose on court — don''t stand in one spot","Your energy sets the ceiling for the session"}', 3);
insert into public.coach_standards (category, items, sort_order) values ('Coaching Every Rep', '{"Every ball hit is an opportunity to coach","Don''t just feed — observe, correct, reinforce","Give feedback in real time, not just at the end","Be specific: "Turn your shoulders earlier" not "Good job"","Hold the standard on every rep, not just the first few"}', 4);
insert into public.coach_standards (category, items, sort_order) values ('Parent Communication', '{"Communicate internally first before talking to families about advancement","Families should only be informed after leadership approval","Avoid speculative language about player movement","Keep communication respectful, growth-focused, and clear","Reinforce that development takes time and should not be rushed"}', 5);
insert into public.coach_standards (category, items, sort_order) values ('What Tier 1 Coaches Are Not', '{"Passive ball feeders","Distracted or disengaged during sessions","Vague or casual in presentation","Lowering standards to avoid discomfort","Prioritizing popularity over development"}', 6);
